InitCaveContinue:
    ; Get this cave's index (object type - $6A).
    ;
    move.b  ($0350,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$6A,D1
    subx.b  D1,D0   ; SBC #$6A
    moveq   #0,D3
    move.b  D0,D3
    ; Get the person text selector by looking up the text selector byte
    ; for this index, and masking it with $3F.
    ;
    lea     (OverworldPersonTextSelectors).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$3F,D0
    move.b  D0,($0415,A4)
    ; Pop and mask the text selector byte with $C0 to get the
    ; "pay" and "pick up" cave flags and store them in [03].
    ;
    move.b  (A5)+,D0  ; PLA
    andi.b #$C0,D0
    move.b  D0,($0003,A4)
    ; At this point, the Y register still has the cave index.
    ; Multiply it by 3 to get the offset of the first item in a set of 3.
    ;
    move.b  #$FD,D0
_anon_z01_0:
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$03,D1
    addx.b  D1,D0   ; ADC #$03 (X flag = 6502 C)
    subq.b  #1,D3
    bpl  _anon_z01_0
    moveq   #0,D3
    move.b  D0,D3
    ; Loop over the wares from 0 to 2.
    ;
    moveq   #0,D2
    even
_L_z01_InitCaveContinue_CopyCaveBytes:
    ; Copy 3 item ID bytes from the Cave level block info.
    ; Item ID's are in the low 6 bits, cave flags are in the high 2 bits.
    ;
    lea     (NES_SRAM+$0A7E).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0422,A4),A0
    move.b  D0,(A0,D2.W)
    ; Copy the cave flags (high 2 bits) of the three items to [00] to [02].
    ;
    andi.b #$C0,D0
    move.b  D0,($00,A4,D2.W)
    ; Copy 3 prices from the Cave level block info.
    ;
    lea     (NES_SRAM+$0ABA).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0430,A4),A0
    move.b  D0,(A0,D2.W)
    ; Bottom of the wares copying loop.
    ;
    addq.b  #1,D3
    addq.b  #1,D2
    cmpi.b  #$03,D2
    bne  _L_z01_InitCaveContinue_CopyCaveBytes
    ; Get the top 2 bits of text selector byte in [03],
    ; shift them to the bottom, and combine them with [00].
    ;
    move.b  ($0003,A4),D0
    lsl.b  #1,D0   ; ASL A
    roxl.b  #1,D0   ; ROL A
    roxl.b  #1,D0   ; ROL A
    move.b  ($0000,A4),D1
    or.b  D1,D0
    move.b  D0,($0000,A4)
    ; Get the top 2 bits of item descriptor 2, shift them right 4 times,
    ; and combine them with [00].
    ;
    move.b  ($0002,A4),D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  ($0000,A4),D1
    or.b  D1,D0
    move.b  D0,($0000,A4)
    ; Get the top 2 bits of item descriptor 1, shift them right twice,
    ; and combine them with [00] into CaveFlags.
    ;
    move.b  ($0001,A4),D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  ($0000,A4),D1
    or.b  D1,D0
    move.b  D0,($0413,A4)
    ; The end result is a byte with 8 cave flags.
    ;
    ; If cave flag "money game" is missing, then go finish up,
    ; instead of choosing random amounts for the money game.
    ;
    andi.b #$20,D0
    beq  _L_z01_InitCaveContinue_ResetTextbox
    ; Determine an index randomly with increasing probability,
    ; from 6 to 1. Start with the following test:
    ;
    ;   If $FF < Random, then go use index 6.
    ;
    move.b  #$FF,D0
    moveq   #6,D3
    even
_L_z01_InitCaveContinue_ChoosePermutation:
    move.b  ($0019,A4),D1
    cmp.b   D1,D0
    bcs  _L_z01_InitCaveContinue_FoundPermutation
    ; If the test fails, then subtract $2B from the reference number.
    ;
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$2B,D1
    subx.b  D1,D0   ; SBC #$2B
    subq.b  #1,D3
    bne  _L_z01_InitCaveContinue_ChoosePermutation
    even
_L_z01_InitCaveContinue_FoundPermutation:
    ; The index chooses the last offset of a permutation of three indexes.
    ;
    moveq   #0,D2
    lea     (MoneyGamePermutationEndIndexes).l,A0
    move.b  (A0,D3.W),D2
    ; Copy the permutation of 3 indexes to [046C] to [046E].
    ;
    moveq   #2,D3
    even
_L_z01_InitCaveContinue_CopyPermutation:
    lea     (MoneyGamePermutations).l,A0
    move.b  (A0,D2.W),D0
    lea     ($046C,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D2
    subq.b  #1,D3
    bpl  _L_z01_InitCaveContinue_CopyPermutation
    ; With the first bit of another random number, choose 10 or 40
    ; to put in [046F]. This is a random amount to lose.
    ;
    move.b  ($001A,A4),D0
    andi.b #$01,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (MoneyGameLossAmounts).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($046F,A4)
    ; Put 10 in [0470]. This is a fixed amount to lose.
    ;
    moveq   #10,D0
    move.b  D0,($0470,A4)
    ; With a different bit of the second random number,
    ; choose 20 or 50 to put in [0471]. This is an amount to win.
    ;
    moveq   #20,D3
    move.b  ($001A,A4),D0
    andi.b #$02,D0
    beq  _anon_z01_1
    moveq   #50,D3
_anon_z01_1:
    move.b  D3,($0471,A4)
    ; The 3 amounts are now in [046F] to [0471].
    ; Reference these amounts using the permutation of indexes
    ; in [046C] to [046E]; and copy them to [0448] to [044A].
    ;
    moveq   #2,D2
    even
_L_z01_InitCaveContinue_ArrangeAmounts:
    moveq   #0,D3
    lea     ($046C,A4),A0
    move.b  (A0,D2.W),D3
    lea     ($046F,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($0448,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bpl  _L_z01_InitCaveContinue_ArrangeAmounts
    even
_L_z01_InitCaveContinue_ResetTextbox:
    ; Reset the current character index.
    ;
    moveq   #0,D0
    move.b  D0,($0416,A4)
    ; Point to the front of the first textbox line.
    ;
    move.b  (TextboxLineAddrsLo+2).l,D0
    move.b  D0,($045F,A4)
    rts

; Params:
; A: X coordinate
; Y: Y coordinate
;
; Set the person's coordinates, HP, and attributes.
;
    even
SetUpCommonCaveObjects:
    move.b  D0,($70,A4,D2.W)
    lea     ($0084,A4),A0
    move.b  D3,(A0,D2.W)
    moveq   #0,D0
    lea     ($0485,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  #$81,D0
    lea     ($04BF,A4),A0
    move.b  D0,(A0,D2.W)
    ; Halt Link.
    ;
    moveq   #64,D0
    move.b  D0,($00AC,A4)
    ; Set up the two bonfires.
    ;
    moveq   #64,D0
    move.b  D0,($0351,A4)
    move.b  D0,($0352,A4)
    moveq   #72,D0
    move.b  D0,($71,A4,D2.W)
    move.b  #$A8,D0
    move.b  D0,($72,A4,D2.W)
    lea     ($0085,A4),A0
    move.b  D3,(A0,D2.W)
    lea     ($0086,A4),A0
    move.b  D3,(A0,D2.W)
    rts

    even
PriceListTemplateTransferBuf:
    dc.b    $22, $C8, $0D, $21, $24, $24, $24, $24
    dc.b    $24, $24, $24, $24, $24, $24, $24, $24
    dc.b    $FF

    even
UpdateCavePerson:
    ; If in state 4, then every other frame skip drawing the person
    ; and items; and go straight to the state code for each kind of cave.
    ;
    move.b  ($00AD,A4),D0
    cmpi.b  #$04,D0
    bne  _anon_z01_2
    move.b  ($0015,A4),D0
    andi.b #$01,D0
    bne  _L_z01_UpdateCavePerson_UpdateCavePersonDirect
_anon_z01_2:
    jsr     DrawCavePerson
    ; If the cave type is not $74 medicine shop,
    ; or it is but the letter has not been used, then
    ; go draw items and run the state code.
    ;
    move.b  ($0350,A4),D0
    cmpi.b  #$74,D0
    bne  _L_z01_UpdateCavePerson_DrawItems
    move.b  ($0666,A4),D0
    cmpi.b  #$02,D0
    beq  _L_z01_UpdateCavePerson_DrawItems
    ; If the letter is selected, and B is pressed, then go use the letter.
    ;
    moveq   #0,D3
    move.b  ($0656,A4),D3
    cmpi.b  #$0F,D3
    bne  _L_z01_UpdateCavePerson_Unhalt
    move.b  ($00F8,A4),D0
    andi.b #$40,D0
    bne  _L_z01_UpdateCavePerson_UseLetter
    even
_L_z01_UpdateCavePerson_Unhalt:
    ; If Link is halted, then unhalt him.
    ;
    move.b  ($00AC,A4),D0
    cmpi.b  #$40,D0
    bne  _anon_z01_3
    jsr     UnhaltLink
_anon_z01_3:
    rts

    even
_L_z01_UpdateCavePerson_UseLetter:
    ; The letter has been used.
    ;
    ; Play the "secret found" tune.
    ;
    moveq   #4,D0
    move.b  D0,($0602,A4)
    ; Set the letter state to used (2).
    ;
    addq.b  #1,($0666,A4)
    ; Change the selected item slot to the potion's.
    ;
    moveq   #7,D0
    move.b  D0,($0656,A4)
    even
_L_z01_UpdateCavePerson_DrawItems:
    jsr     DrawCaveItems
    even
_L_z01_UpdateCavePerson_UpdateCavePersonDirect:
    move.b  ($00AD,A4),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateCavePerson_JumpTable:
    dc.l    UpdateCavePersonState_TransferPrices   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdatePersonState_Textbox   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateCavePersonState_TalkOrShopOrDoorCharge   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdatePersonState_CueTransferBlankPersonWares   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdatePersonState_DelayThenHide   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateCavePersonState_HintOrMoneyGame   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdatePersonState_CueTransferBlankPersonWares   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdatePersonState_Textbox   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateCavePersonState_DoNothing   ; jump table entry (32-bit for _m68k_tablejump)

    even
DrawCavePerson:
    jsr     Anim_FetchObjPosForSpriteDescriptor
    ; If the cave/person type >= $7B, then the visual is a moblin.
    ; So, go draw not mirrored.
    ;
    moveq   #0,D3
    move.b  ($0350,A4),D3
    cmpi.b  #$7B,D3
    bcc  _anon_z01_4
    ; Else the old man, old woman, and shopkeeper are all mirrored.
    ;
    jmp     DrawObjectMirrored

_anon_z01_4:
    jmp     DrawObjectNotMirrored

    even
CaveWareXs:
    dc.b    $58, $78, $98

    even
DrawCaveItems:
    ; If the cave flags do not call for showing items, then
    ; go see about showing prices.
    ;
    move.b  ($0413,A4),D0
    andi.b #$04,D0
    beq  _L_z01_DrawCaveItems_ShowPriceRupee
    ; Loop over the wares to draw, from 2 to 0, indexed by [0421].
    ;
    moveq   #2,D0
    move.b  D0,($0421,A4)
    even
_L_z01_DrawCaveItems_LoopWare:
    moveq   #0,D2
    move.b  ($0421,A4),D2
    ; Look up and set the X coordinate for the current item.
    ;
    lea     (CaveWareXs).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0083,A4)
    ; Set Y coordinate $98 for the item.
    ;
    move.b  #$98,D0
    move.b  D0,($0097,A4)
    ; If the item is nothing ($3F), then loop gain.
    ;
    lea     ($0422,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$3F,D0
    cmpi.b  #$3F,D0
    beq  _L_z01_DrawCaveItems_NextWare
    ; Switch to the room item object slot, and draw it.
    ;
    moveq   #19,D2
    jsr     AnimateItemObject
    even
_L_z01_DrawCaveItems_NextWare:
    ; Bottom of the item drawing loop. Decrement this index until < 0.
    ;
    subq.b  #1,($0421,A4)
    bpl  _L_z01_DrawCaveItems_LoopWare
    even
_L_z01_DrawCaveItems_ShowPriceRupee:
    ; If the cave flags do not call for showing prices, then return.
    ;
    move.b  ($0413,A4),D0
    andi.b #$08,D0
    beq  _L_z01_DrawCaveItems_Exit
    ; Show a rupee at ($30, $AB).
    ;
    moveq   #48,D0
    move.b  D0,($0083,A4)
    move.b  #$AB,D0
    move.b  D0,($0097,A4)
    moveq   #24,D0
    moveq   #19,D2
    jsr     AnimateItemObject
    even
_L_z01_DrawCaveItems_Exit:
    rts

    even
UpdateCavePersonState_TransferPrices:
    ; If the cave flags do not call for showing prices, then
    ; advance the state and return.
    ;
    move.b  ($0413,A4),D0
    andi.b #$08,D0
    bne.s  __far_z_01_0002
    jmp  IncCaveState
__far_z_01_0002:
    even
WritePricesTransferBuf:
    jsr     CopyPriceListTemplate
    moveq   #33,D0
; Params:
; A: price character
;
    even
WritePricesToDynamicTransferBuf:
    move.b  D0,($0305,A4)
    ; Reset the index of current price being formatted
    ; and offset of price string.
    ;
    moveq   #0,D2
    move.b  D2,($042E,A4)
    move.b  D2,($042F,A4)
    even
_L_z01_WritePricesToDynamicTransferBuf_LoopPrice:
    ; Get the price of the current item.
    ;
    lea     ($0430,A4),A0
    move.b  (A0,D2.W),D0
    ; If it's 0, then store a space character in the text field [01], [02], [03].
    ;
    bne  _L_z01_WritePricesToDynamicTransferBuf_Format
    moveq   #36,D2
    move.b  D2,($0001,A4)
    move.b  D2,($0002,A4)
    move.b  D2,($0003,A4)
    jmp     _L_z01_WritePricesToDynamicTransferBuf_Align

    even
_L_z01_WritePricesToDynamicTransferBuf_Format:
    jsr     FormatDecimalByte
    ; If the cave flags call for negative amounts, then
    ; store a dash in prefix byte [04]. Else store a space ($24).
    ;
    moveq   #36,D2
    move.b  ($0413,A4),D0
    lsl.b  #1,D0   ; ASL A
    bcc  _L_z01_WritePricesToDynamicTransferBuf_Align
    moveq   #98,D2
    even
_L_z01_WritePricesToDynamicTransferBuf_Align:
    move.b  D2,($0004,A4)
    ; Move the dash closer to the number.
    ;
    moveq   #0,D3
    move.b  ($042F,A4),D3
    move.b  ($0002,A4),D0
    jsr     SwapSpaceAndSign
    lea     ($0308,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  ($0001,A4),D0
    jsr     SwapSpaceAndSign
    lea     ($0307,A4),A0
    move.b  D0,(A0,D3.W)
    move.b  ($0003,A4),D0
    lea     ($0309,A4),A0
    move.b  D0,(A0,D3.W)
    ; Add 4 to the base offset for the next string.
    ;
    move.b  ($042F,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    move.b  D0,($042F,A4)
    ; Bottom of the price loop. Increment the index of the item until = 3.
    ;
    addq.b  #1,($042E,A4)
    moveq   #0,D2
    move.b  ($042E,A4),D2
    cmpi.b  #$03,D2
    bne  _L_z01_WritePricesToDynamicTransferBuf_LoopPrice
    ; Delay $A frames at the beginning of the next state.
    ;
    moveq   #10,D0
    move.b  D0,($0029,A4)
    ; Go to the next state and return.
    ;
    beq.s  __far_z_01_0003
    jmp  IncCaveState
__far_z_01_0003:
; Params:
; A: selector
;
    even
CueTransferBufAndAdvanceState:
    move.b  D0,($0014,A4)
    even
IncCaveState:
    addq.b  #1,($00AD,A4)
    rts

; Params:
; A: a character of the price string
; [04]: prefix character
;
; Returns:
;   If original A is not a space:
;     A:    original character
;     [04]: original prefix character
;   Else:
;     A:    original prefix character
;     [04]: original character
;
    even
SwapSpaceAndSign:
    cmpi.b  #$24,D0
    bne  _anon_z01_5
    moveq   #0,D2
    move.b  D0,D2
    move.b  ($0004,A4),D0
    move.b  D2,($0004,A4)
_anon_z01_5:
    rts

    even
CopyPriceListTemplate:
    ; Copy $11 bytes of the price list template text to the dynamic transfer buf.
    ;
    moveq   #16,D3
_anon_z01_6:
    lea     (PriceListTemplateTransferBuf).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z01_6
    rts

    even
TextboxCharTransferRecTemplate:
    dc.b    $21, $A4, $01, $24, $FF

    even
TextboxLineAddrsLo:
    dc.b    $C4, $E4, $A4

    even
UpdatePersonState_Textbox:
    jsr     Link_EndMoveAndDraw_Bank1
    ; If the person's timer has not expired, then return.
    ;
    move.b  ($0029,A4),D0
    bne  _L_z01_UpdatePersonState_Textbox_Exit
    ; Set the timer to wait 6 frames after the next character about
    ; to be shown.
    ;
    moveq   #6,D0
    move.b  D0,($0029,A4)
    ; Copy the 5 bytes of the textbox character transfer record template
    ; to the dynamic transfer buf.
    ;
    moveq   #4,D3
_anon_z01_7:
    lea     (TextboxCharTransferRecTemplate).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z01_7
    even
_L_z01_UpdatePersonState_Textbox_WriteChar:
    ; Replace the low byte of the VRAM address with the one
    ; where the next character should be written.
    ;
    move.b  ($045F,A4),D0
    move.b  D0,($0303,A4)
    ; Increment the low VRAM address for the next character.
    ;
    addq.b  #1,($045F,A4)
    ; Use the person text selector to look up the address of the
    ; text for the textbox. Store the address in [00:01].
    ;
    moveq   #0,D3
    move.b  ($0415,A4),D3
    lea     (PersonTextAddrs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0000,A4)
    addq.b  #1,D3
    lea     (PersonTextAddrs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0001,A4)
    ; Load the person text current character index.
    ;
    moveq   #0,D3
    move.b  ($0416,A4),D3
    ; Increment the index variable to point to the next character
    ; for next time.
    ;
    addq.b  #1,($0416,A4)
    ; Get the current character.
    ;
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    ; If the character is $25, then it's a special space. It will still
    ; take up space, but will not take time to show -- meaning that
    ; we'll go look up the next character to transfer.
    ;
    andi.b #$3F,D0
    cmpi.b  #$25,D0
    beq  _L_z01_UpdatePersonState_Textbox_WriteChar
    ; We have a non-space character. Put it in the transfer record.
    ;
    move.b  D0,($0305,A4)
    ; Play the "heart taken/character" sound effect.
    ;
    moveq   #16,D0
    move.b  D0,($0604,A4)
    ; If the high 2 bits of character element = 0, then return.
    ;
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    andi.b #$C0,D0
    beq  _L_z01_UpdatePersonState_Textbox_Exit
    ; Determine an index based on the high 2 bits of the character element:
    ;   $80: 0
    ;   $40: 1
    ;   $C0: 2
    ;
    moveq   #2,D3
    cmpi.b  #$C0,D0
    beq  _L_z01_UpdatePersonState_Textbox_ChangeLine
    subq.b  #1,D3
    cmpi.b  #$40,D0
    beq  _L_z01_UpdatePersonState_Textbox_ChangeLine
    subq.b  #1,D3
    even
_L_z01_UpdatePersonState_Textbox_ChangeLine:
    ; The index chooses the low VRAM address of the start
    ; of another line:
    ;   0: $C4: front of the second line
    ;   1: $E4: front of the third line
    ;   2: $A4: front of the first line
    ;
    ; Look up the low VRAM address and store it.
    ;
    lea     (TextboxLineAddrsLo).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($045F,A4)
    ; If index = 2, then we've reached the end of the text,
    ; and low VRAM address is moved to the front of the first line.
    ; So, advance the state of the person object, and unhalt Link.
    ;
    cmpi.b  #$02,D3
    bne  _L_z01_UpdatePersonState_Textbox_Exit
    addq.b  #1,($00AD,A4)
    jsr     UnhaltLink
    even
_L_z01_UpdatePersonState_Textbox_Exit:
    rts

    even
UpdateCavePersonState_TalkOrShopOrDoorCharge:
    ; If the cave flags call for choosing an item, then
    ; go handle those kinds of caves.
    ;
    move.b  ($0413,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_CheckPickUp
    ; Advance to the end state, where the person is still shown.
    ;
    moveq   #8,D0
    move.b  D0,($00AD,A4)
    ; If this is not the "door charge" old man, then return.
    ; The person only talks.
    ;
    move.b  ($0350,A4),D0
    cmpi.b  #$71,D0
    bne  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_Exit
    ; Post 20 rupees to subtract.
    ;
    move.b  ($067E,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$14,D1
    addx.b  D1,D0   ; ADC #$14 (X flag = 6502 C)
    move.b  D0,($067E,A4)
    ; Mark this secret taken.
    ;
    jsr     SetRoomFlagUWItemState
    even
_L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_Exit:
    rts

    even
_L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_CheckPickUp:
    ; This is a cave where the player chooses or touches an item:
    ; - give item
    ; - shop
    ; - hint
    ; - money game
    ;
    ; If rupees are decreasing, then return.
    ;
    move.b  ($067E,A4),D0
    bne  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_Exit
    ; Loop over each item from 2 to 0.
    ;
    moveq   #2,D2
    even
_L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_LoopWare:
    ; If this item is nothing, then loop again.
    ;
    lea     ($0422,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$3F,D0
    cmpi.b  #$3F,D0
    beq  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_NextWare
    ; If Link's X <> item's X, then loop again.
    ;
    move.b  ($0070,A4),D0
    lea     (CaveWareXs).l,A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bne  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_NextWare
    ; If the vertical distance between Link and the item < 6, then
    ; go try to take it.
    ;
    move.b  ($0084,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$98,D1
    subx.b  D1,D0   ; SBC #$98
    jsr     Abs
    cmpi.b  #$06,D0
    bcs  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_PickedUp
    even
_L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_NextWare:
    ; Bottom of the item touch loop.
    ;
    subq.b  #1,D2
    bpl  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_LoopWare
    rts

    even
_L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_PickedUp:
    ; Store the index of the item chosen.
    ;
    move.b  D2,($0438,A4)
    ; If hint and money game cave flags are missing, then
    ; go take an item given away, or buy it.
    ;
    move.b  ($0413,A4),D0
    andi.b #$30,D0
    beq  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_PickedUpWare
    ; If have cave flag "money game", then go to state 5 and return.
    ;
    andi.b #$10,D0
    beq  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_MadeWager
    ; Else have "hint" cave flag.
    ;
    ; If rupees < price, then return.
    ;
    move.b  ($066D,A4),D0
    lea     ($0430,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bcc.s  __far_z_01_0004
    jmp  Exit
__far_z_01_0004:
    ; Pass the price to pay for the hint.
    ;
    lea     ($0430,A4),A0
    move.b  (A0,D2.W),D0
    jsr     PostDebit
    even
_L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_MadeWager:
    ; Go to state 5. It runs the hint cave and money game.
    ;
    moveq   #5,D0
    move.b  D0,($00AD,A4)
    rts

    even
_L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_PickedUpWare:
    ; This is a shop, or something is being given away.
    ;
    ; If "pay" cave flag is missing, then go try to take the item.
    ;
    move.b  ($0413,A4),D0
    andi.b #$02,D0
    beq  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_TryToTake
    ; If rupees < price, then return.
    ;
    move.b  ($066D,A4),D0
    lea     ($0430,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bcc.s  __far_z_01_0005
    jmp  Exit
__far_z_01_0005:
    ; Pass the price to pay for the item.
    ;
    lea     ($0430,A4),A0
    move.b  (A0,D2.W),D0
    jsr     PostDebit
    even
_L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_TryToTake:
    ; If "heart requirement" cave flag is missing, then
    ; go to take the item without further ado.
    ;
    move.b  ($0413,A4),D0
    andi.b #$40,D0
    beq  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_Take
    ; Check heart container requirements.
    ;
    ; 5 is the minimum for cave type $6C (white sword)
    ; $C is the minimum otherwise
    ;
    moveq   #64,D3
    move.b  ($0350,A4),D0
    cmpi.b  #$6C,D0
    beq  _anon_z01_8
    move.b  #$B0,D3
_anon_z01_8:
    move.b  ($066F,A4),D1
    cmp.b   D1,D3
    ; If the minimum of heart containers is met, then
    ; go take the item without further ado.
    ;
    beq  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_Take
    bcc  _L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_Take
    rts

