_L_z01_UpdateCavePersonState_TalkOrShopOrDoorCharge_Take:
    jsr     SetRoomFlagUWItemState
    lea     ($0422,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$3F,D0
    move.b  D0,-(A5)  ; PHA
