_L_z01_UpdateCavePersonState_HintOrMoneyGame_HandleMoneyGameOrGiveaway:
    ; If cave type < $7B, then go handle the money game.
    ;
    ; This is a moblin giving away money.
    ;
    move.b  ($0350,A4),D0
    cmpi.b  #$7B,D0
    bcs  _L_z01_UpdateCavePersonState_HintOrMoneyGame_HandleMoneyGame
    jsr     CopyPriceListTemplate
    ; Write a price list into the dynamic transfer buf,
    ; but with a space instead of "X".
    ;
    moveq   #36,D0
    jsr     WritePricesToDynamicTransferBuf
    moveq   #8,D0
    move.b  D0,($0604,A4)
    jsr     SetRoomFlagUWItemState
    ; Go to state 8 to do nothing but show the person.
    ;
    moveq   #8,D0
    move.b  D0,($00AD,A4)
    ; Post the middle amount in [0431] to add.
    ;
    move.b  ($0431,A4),D0
    jmp     PostCredit

    even
_L_z01_UpdateCavePersonState_HintOrMoneyGame_HandleMoneyGame:
    ; Money game
    ;
    ; If rupees < $A, then return.
    ;
    move.b  ($066D,A4),D0
    cmpi.b  #$0A,D0
    bcc.s  __far_z_01_0007
    jmp  L493A_Exit
__far_z_01_0007:
    moveq   #8,D0
    move.b  D0,($0604,A4)
    ; Copy amounts in [0448][Y] for money game to prices [0430][Y].
    ;
    moveq   #2,D3
_anon_z01_10:
    lea     ($0448,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($0430,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,D3
    bpl  _anon_z01_10
    jsr     WritePricesTransferBuf
    ; Go to state 8 to do nothing but show the person.
    ;
    moveq   #8,D0
    move.b  D0,($00AD,A4)
    ; Prepend the sign to each money game amount.
    ;
    moveq   #1,D3
    move.b  ($0448,A4),D0
    jsr     PrependSignToPrice
    moveq   #5,D3
    move.b  ($0449,A4),D0
    jsr     PrependSignToPrice
    moveq   #9,D3
    move.b  ($044A,A4),D0
    jsr     PrependSignToPrice
    ; If the amount chosen = 20 or 50, then add it;
    ; else subtract it.
    ;
    moveq   #0,D2
    move.b  ($0438,A4),D2
    lea     ($0448,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$14,D0
    bne.s  __far_z_01_0008
    jmp  PostCredit
__far_z_01_0008:
    cmpi.b  #$32,D0
    beq.s  __far_z_01_0009
    jmp  PostDebit
__far_z_01_0009:
    even
PostCredit:
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($067D,A4),D1
    addx.b  D1,D0   ; ADC RupeesToAdd
    move.b  D0,($067D,A4)
    rts

; Params:
; A: amount
;
; Add the amount paid to the rupees to subtract.
;
    even
PostDebit:
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($067E,A4),D1
    addx.b  D1,D0   ; ADC RupeesToSubtract
    move.b  D0,($067E,A4)
    rts

; Params:
; A: price
; Y: offset from first character after "X"
;
; If the amount is $14 or $32, then use "+", else "-".
;
    even
PrependSignToPrice:
    moveq   #100,D2
    cmpi.b  #$14,D0
    beq  _anon_z01_11
    cmpi.b  #$32,D0
    beq  _anon_z01_11
    moveq   #98,D2
_anon_z01_11:
    ; Copy the character to the first element after the "X",
    ; offset by the parameter.
    ;
    move.b  D2,D0
    lea     ($0306,A4),A0
    move.b  D0,(A0,D3.W)
