    bcs  _L_z01_UpdateUnderworldPersonComplexState_SenseLink_CheckCanPay
    even
_L_z01_UpdateUnderworldPersonComplexState_SenseLink_Exit:
    rts

    even
_L_z01_UpdateUnderworldPersonComplexState_SenseLink_CheckCanPay:
    ; If rupee count < 100, then return.
    ;
    moveq   #100,D0
    move.b  ($066D,A4),D1
    cmp.b   D1,D0
    beq  _anon_z01_16
    bcs  _L_z01_UpdateUnderworldPersonComplexState_SenseLink_Exit
_anon_z01_16:
    ; Post 100 rupees more to subtract.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($067E,A4),D1
    addx.b  D1,D0   ; ADC RupeesToSubtract
    move.b  D0,($067E,A4)
    ; Play the "key taken" sound effect.
    ;
    moveq   #8,D0
    move.b  D0,($0604,A4)
    ; Increase max bombs by 4, set the amount on hand to the max.
    ;
    move.b  ($067C,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    move.b  D0,($067C,A4)
    move.b  D0,($0658,A4)
    ; Go mark this offer taken.
    ;
    jmp     L_Person_FlagItemTakenAndAdvanceState

    even
UpdateUnderworldPersonComplexState_DelayAndQuit:
    ; If the object timer has expired, then destroy this object.
    ;
    move.b  ($0029,A4),D0
    bne  _anon_z01_17
    move.b  D0,($0350,A4)
_anon_z01_17:
    rts

    even
Person_DrawAndCheckCollisions:
    jsr     Person_CheckCollisions
    jsr     Anim_FetchObjPosForSpriteDescriptor
    jmp     DrawObjectMirrored

    even
UpdateUnderworldPersonLifeOrMoney_Full:
    ; In state 4, this person and the items are drawn every other frame.
    ;
    move.b  ($00AD,A4),D0
    cmpi.b  #$04,D0
    bne  _L_z01_UpdateUnderworldPersonLifeOrMoney_Full_Draw
    move.b  ($0015,A4),D0
    andi.b #$01,D0
    bne  _anon_z01_18
    even
_L_z01_UpdateUnderworldPersonLifeOrMoney_Full_Draw:
    jsr     Person_DrawAndCheckCollisions
    jsr     DrawLifeOrMoneyItems
_anon_z01_18:
    move.b  ($00AD,A4),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateUnderworldPersonLifeOrMoney_Full_JumpTable:
    dc.l    UpdateUnderworldPersonLifeOrMoneyState_0   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdatePersonState_Textbox   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateUnderworldPersonLifeOrMoneyState_2   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdatePersonState_CueTransferBlankPersonWares   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateUnderworldPersonComplexState_DelayAndQuit   ; jump table entry (32-bit for _m68k_tablejump)

    even
LifeOrMoneyItemXs:
    dc.b    $58, $98

    even
LifeOrMoneyItemTypes:
    dc.b    $1A, $18

    even
DrawLifeOrMoneyItems:
    ; Loop over each item to draw, from 1 to 0.
    ;
    moveq   #1,D2
    even
_L_z01_DrawLifeOrMoneyItems_LoopWare:
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    ; Look up and set the X coordinate of the item.
    ;
    lea     (LifeOrMoneyItemXs).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0083,A4)
    ; Set Y=$98, and look up the item type.
    ;
    move.b  #$98,D0
    move.b  D0,($0097,A4)
    lea     (LifeOrMoneyItemTypes).l,A0
    move.b  (A0,D2.W),D0
    ; Switch to the room item object slot.
    ;
    moveq   #19,D2
    jsr     AnimateItemObject
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    subq.b  #1,D2
    bpl  _L_z01_DrawLifeOrMoneyItems_LoopWare
    rts

    even
UpdateUnderworldPersonLifeOrMoneyState_0:
    ; Delay in the next state $A frames before showing the first character.
    ;
    moveq   #10,D0
    move.b  D0,($0029,A4)
    moveq   #118,D0
    jmp     CueTransferBufAndAdvanceState

    even
UpdateUnderworldPersonLifeOrMoneyState_2:
    ; Loop over each item to check, from 1 to 0.
    ;
    moveq   #1,D2
    even
_L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_LoopWare:
    ; If Link's X doesn't match the item's, then go loop again.
    ;
    move.b  ($0070,A4),D0
    lea     (LifeOrMoneyItemXs).l,A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bne  _L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_NextWare
    ; If the vertical distance between the item and Link < 6, then
    ; go handle paying appropriately.
    ;
    move.b  ($0084,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$98,D1
    subx.b  D1,D0   ; SBC #$98
    jsr     Abs
    cmpi.b  #$06,D0
    bcs  _L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_Pay
    even
_L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_NextWare:
    subq.b  #1,D2
    bpl  _L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_LoopWare
    even
_L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_Exit:
    rts

    even
_L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_Pay:
    ; If the player chose the heart container, go handle it.
    ;
    cmpi.b  #$00,D2
    beq  _L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_PayWithHeartContainer
    ; The player chose the money.
    ; But if he doesn't have enough, then return.
    ;
    moveq   #50,D0
    move.b  ($066D,A4),D1
    cmp.b   D1,D0
    beq  _L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_PayWithMoney
    bcs  _L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_Exit
    even
_L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_PayWithMoney:
    ; Post 50 rupees more to subtract, and go flag this offer taken.
    ;
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($067E,A4),D1
    addx.b  D1,D0   ; ADC RupeesToSubtract
    move.b  D0,($067E,A4)
    jmp     _L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_EndLifeOrMoney

    even
_L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_PayWithHeartContainer:
    ; The player chose the heart container.
    ;
    ; If the number of heart containers < 4, then
    ; - leave the number of heart containers alone
    ; - set HeartPartial to 0, so Link will die with one more hit
    ;
    ; Then go flag this offer taken.
    ;
    move.b  ($066F,A4),D0
    andi.b #$F0,D0
    cmpi.b  #$30,D0
    bcc  _L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_Reduce
    move.b  D0,($066F,A4)
    moveq   #0,D0
    move.b  D0,($0670,A4)
    jmp     _L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_EndLifeOrMoney

    even
_L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_Reduce:
    ; Store (HeartValues - 1 heart container) in [00].
    ;
    move.b  ($066F,A4),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$F0,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$10,D1
    subx.b  D1,D0   ; SBC #$10
    move.b  D0,($0000,A4)
    ; Get (HeartValues - 1 heart)
    ;
    move.b  (A5)+,D0  ; PLA
    andi.b #$0F,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$01,D1
    subx.b  D1,D0   ; SBC #$01
    ; If the result is negative, then make the full hearts 0.
    ;
    bpl  _anon_z01_19
    moveq   #0,D0
_anon_z01_19:
    ; Combine the heart containers and full hearts, and store it.
    ;
    move.b  ($0000,A4),D1
    or.b  D1,D0
    move.b  D0,($066F,A4)
    even
_L_z01_UpdateUnderworldPersonLifeOrMoneyState_2_EndLifeOrMoney:
    moveq   #8,D0
    move.b  D0,($0604,A4)
    moveq   #1,D0
    move.b  D0,($04CE,A4)
    jmp     L_Person_FlagItemTakenAndAdvanceState

    even
UpdateGrumble_Full:
    ; If state <> 3, then go check collisions and draw every frame.
    ;
    move.b  ($00AD,A4),D0
    cmpi.b  #$03,D0
    bne  _L_z01_UpdateGrumble_Full_DrawAndCheckCollisions
    ; In state 3, the person is translucent by drawing
    ; (and checking object collisions) every other frame.
    ;
    move.b  ($0015,A4),D0
    andi.b #$01,D0
    bne  _anon_z01_20
    even
_L_z01_UpdateGrumble_Full_DrawAndCheckCollisions:
    jsr     Person_CheckCollisions
    jsr     Anim_FetchObjPosForSpriteDescriptor
    jsr     DrawObjectNotMirrored
_anon_z01_20:
    move.b  ($00AD,A4),D0
    jsr     _m68k_tablejump  ; M68K-native table dispatch (replaces JSR TableJump)
    even
UpdateGrumble_Full_JumpTable:
    dc.l    UpdatePersonState_Textbox   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateGrumble1   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdatePersonState_CueTransferBlankPersonWares   ; jump table entry (32-bit for _m68k_tablejump)
    dc.l    UpdateGrumble3   ; jump table entry (32-bit for _m68k_tablejump)

    even
UpdateGrumble1:
    ; If there's no food in object slot $F, then return.
    ;
    moveq   #15,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    lsl.b  #1,D0   ; ASL A
    bcs.s  __far_z_01_0014
    jmp  InitUnderworldPerson_DoNothing
__far_z_01_0014:
    ; Else halt Link and play the "secret found" tune.
    ;
    moveq   #64,D0
    move.b  D0,($00AC,A4)
    moveq   #4,D0
    move.b  D0,($0602,A4)
    even
L_Person_FlagItemTakenAndAdvanceState:
    ; Flag the secret/item of this room taken.
    ;
    jsr     SetRoomFlagUWItemState
    ; Set object timer $40 for when we get to state 3.
    ;
    moveq   #64,D0
    move.b  D0,($0029,A4)
    ; Cue transfer record of the blank textbox lines,
    ; and go to the next state, where a transfer record is cued
    ; to clear cave/person wares.
    ;
    moveq   #30,D0
    jmp     CueTransferBufAndAdvanceState

    even
UpdateGrumble3:
    jsr     Link_EndMoveAndAnimate_Bank1
    ; If the timer has not expired, then return.
    ;
    move.b  ($0029,A4),D0
    beq.s  __far_z_01_0015
    jmp  InitUnderworldPerson_DoNothing
__far_z_01_0015:
    ; Deactivate the food object in slot $F.
    ;
    moveq   #15,D3
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D3.W)
    ; Get rid of the food from the inventory.
    ;
    move.b  D0,($065D,A4)
    ; Make Link idle again, and reset this object's type.
    ;
    move.b  D0,($00AC,A4)
    move.b  D0,($0350,A4)
    even
InitUnderworldPerson_DoNothing:
    rts

