CopyCommonCodeToRam:
    ; PATCHED: NOP — all code is in flat ROM on Genesis.
    rts
    moveq   #0,D0
    move.b  D0,($0000,A4)
    move.b  #$A5,D0
    move.b  D0,($0001,A4)
    move.b  #$90,D0
    move.b  D0,($0002,A4)
    moveq   #108,D0
    move.b  D0,($0003,A4)
    moveq   #0,D3
    even
_L_z01_CopyCommonCodeToRam_Loop:
    move.b  ($00,A4),D1   ; ptr lo
    move.b  ($01,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
    movea.l D4,A0
    move.b  (A0,D3.W),D0     ; LDA ($nn),Y
    move.b  ($02,A4),D1   ; ptr lo
    move.b  ($03,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4
    ext.l   D4
    add.l   #NES_RAM,D4
    movea.l D4,A0
    move.b  D0,(A0,D3.W)     ; STA ($nn),Y
    ; Increment source address.
    ;
    move.b  ($0000,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    move.b  D0,($0000,A4)
    move.b  ($0001,A4),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    move.b  D0,($0001,A4)
    ; Increment destination address.
    ;
    move.b  ($0002,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
    move.b  D0,($0002,A4)
    move.b  ($0003,A4),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    move.b  D0,($0003,A4)
    cmpi.b  #$7F,D0
    bne  _L_z01_CopyCommonCodeToRam_Loop
    move.b  ($0002,A4),D0
    cmpi.b  #$00,D0
    bne  _L_z01_CopyCommonCodeToRam_Loop
    rts

    even
DemoPatternBlockAddrs:
    dc.l    DemoSpritePatterns        ; 32-bit Genesis ROM address
    dc.l    DemoBackgroundPatterns     ; 32-bit Genesis ROM address

    even
DemoPatternBlockSizes:
    dc.w    $0900
    dc.w    $0820

    even
DemoPatternVramAddrs:
    dc.w    $0700
    dc.w    $1700

    even
TransferDemoPatterns:
    jsr     TurnOffAllVideo
    jsr     _ppu_read_2  ; PPU $2002 read → D0
    even
_L_z01_TransferDemoPatterns_LoopBlock:
    ; Loop over each block.
    ;
    move.b  ($051D,A4),D0
    lsl.b  #1,D0   ; ASL A
    moveq   #0,D2
    move.b  D0,D2
    ; Put block address in [00:01] and size in [03:02].
    ; Load destination VRAM address and set it.
    ; The size and VRAM address have the high byte first.
    ;
    lea     (DemoPatternBlockAddrs).l,A0
    move.w  D2,D5
    add.w   D5,D5              ; D5 = 4*block_idx (dc.l = 4 bytes)
    move.l  (A0,D5.W),D5      ; D5 = 32-bit Genesis ROM source addr
    move.l  D5,($04,A4)       ; store to [$04:$07]
    lea     (DemoPatternBlockSizes).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0002,A4)
    lea     (DemoPatternVramAddrs).l,A0
    move.b  (A0,D2.W),D0
    jsr     _ppu_write_6  ; PPU $2006 write, D0=val
    addq.b  #1,D2
    ; (32-bit Genesis ROM addr already in [$04:$07])
    lea     (DemoPatternBlockSizes).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0003,A4)
    lea     (DemoPatternVramAddrs).l,A0
    move.b  (A0,D2.W),D0
    jsr     TransferPatternBlock_Bank1
    ; Loop until pattern block index = 2.
    ;
    move.b  ($051D,A4),D0
    cmpi.b  #$02,D0
    bne  _L_z01_TransferDemoPatterns_LoopBlock
    move.b  #$A5,D0
    move.b  D0,($00F6,A4)
    moveq   #0,D0
    move.b  D0,($051D,A4)
    rts

; Params:
; [00:01]: source address
; [03:02]: size
; A: low byte of desination VRAM address
;
    even
TransferPatternBlock_Bank1:
    ; PATCHED: fast bulk CHR transfer (bypasses per-byte _ppu_write_7)
    jsr     _ppu_write_6          ; complete PPU addr latch pair (sets PPU_VADDR)
    movea.l ($04,A4),A0           ; ROM source address
    move.w  (PPU_VADDR).l,D1      ; NES CHR destination address
    moveq   #0,D2
    move.b  ($0002,A4),D2         ; size hi byte
    lsl.w   #8,D2
    move.b  ($0003,A4),D2         ; size lo byte (D2.w = total bytes)
    ext.l   D2                    ; D2.l = byte count
    jsr     _transfer_chr_block_fast
    addq.b  #1,($051D,A4)         ; increment block index
    rts

    even
