; Params:
; A: Y coordinate
; X: object index
;
    even
InitWhirlwind:
    move.b  D0,($0084,A4)
; Params:
; X: object index
;
;
; Set the whirlwind's Y to Link's, X to 0, and type $2E.
;
    even
SetUpWhirlwind:
    move.b  ($0084,A4),D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #0,D0
    move.b  D0,($70,A4,D2.W)
    moveq   #46,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
WhirlwindPrevRoomIdList:
    dc.b    $36, $3B, $73, $44, $0A, $21, $41, $6C

    even
UpdateWhirlwind_Full:
    ; Get Link's halted state.
    ;
    move.b  ($00AC,A4),D0
    andi.b #$40,D0
    moveq   #0,D3
    move.b  D0,D3
    ; Add 2 to whirlwind X.
    ;
    moveq   #2,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($70,A4,D2.W),D1
    addx.b  D1,D0   ; ADC ObjX,X
    move.b  D0,($70,A4,D2.W)
    ; If Link is not halted or teleporting state = 0, then
    ; go check for collision with Link.
    ;
    cmpi.b  #$40,D3
    bne  _L_z01_UpdateWhirlwind_Full_CheckCollision
    moveq   #0,D3
    move.b  ($0522,A4),D3
    beq  _L_z01_UpdateWhirlwind_Full_CheckCollision
    ; Else Link is halted (state $40) and teleporting state <> 0.
    ;
    ; Set Link's X to whirlwind's.
    ;
    move.b  D0,($0070,A4)
    ; If teleporting state = 1 or whirlwind's X <> $80, go check
    ; the right screen edge and draw.
    ;
    subq.b  #1,D3
    beq  _L_z01_UpdateWhirlwind_Full_CheckRightEdge
    cmpi.b  #$80,D0
    bne  _L_z01_UpdateWhirlwind_Full_CheckRightEdge
    ; Teleporting state = 2 and whirlwind's X = $80.
    ;
    ; Reset Link's state, teleporting state, and whirlwind object type.
    ;
    lsl.b  #1,D0   ; ASL A
    move.b  D0,($00AC,A4)
    move.b  D0,($0522,A4)
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    ; Update the player position marker, and draw one last time.
    ;
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    jsr     UpdatePlayerPositionMarker
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    jmp     _L_z01_UpdateWhirlwind_Full_Draw

    even
_L_z01_UpdateWhirlwind_Full_CheckCollision:
    ; Link is not halted or teleporting state = 0.
    ; Try to pick up Link.
    ;
    ; If the whirlwind does not collide with Link, then go check
    ; for the screen's right edge.
    ;
    jsr     CheckLinkCollision
    move.b  ($0006,A4),D0
    beq  _L_z01_UpdateWhirlwind_Full_CheckRightEdge
    ; Collided with Link.
    ;
    ; Make Link face right. Reset shove info and subroom type.
    ;
    moveq   #1,D0
    move.b  D0,($0098,A4)
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($00C0,A4)
    move.b  D0,($00D3,A4)
    move.b  D0,($005A,A4)
    ; Halt Link (state $40), and hide him.
    ;
    moveq   #64,D0
    move.b  D0,($00AC,A4)
    move.b  #$F8,D0
    move.b  D0,($0248,A4)
    move.b  D0,($024C,A4)
    ; Find and set the room that will behave as the previous room
    ; when scrolling right to the room with the level's entrance.
    ;
    move.b  ($0523,A4),D0
    andi.b #$07,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (WhirlwindPrevRoomIdList).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($00EA,A4)
    ; Set teleporting state 1.
    ;
    addq.b  #1,($0522,A4)
    even
_L_z01_UpdateWhirlwind_Full_CheckRightEdge:
    ; If whirlwind's X < $F0, go draw.
    ;
    move.b  ($70,A4,D2.W),D0
    cmpi.b  #$F0,D0
    bcs  _L_z01_UpdateWhirlwind_Full_Draw
    ; The whirlwind has reached the right edge of the screen.
    ;
    ; Destroy the object.
    ;
    jsr     DestroyWhirlwind
    ; If teleporting state <> 0, we picked up Link.
    ; So, go to the next mode.
    ;
    ; Either way, draw one last time.
    ;
    move.b  ($0522,A4),D0
    beq  _L_z01_UpdateWhirlwind_Full_Draw
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    jsr     GoToNextModeFromPlay
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z01_UpdateWhirlwind_Full_Draw:
    jmp     DrawWhirlwind

    even
DestroyWhirlwind:
    moveq   #0,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($00C0,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($00D3,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D0,($28,A4,D2.W)
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($04F0,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  #$FF,D0
    lea     ($0492,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #1,D0
    lea     ($0405,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
SummonWhirlwind:
    ; If not in mode 5, return.
    ;
    move.b  ($0012,A4),D0
    cmpi.b  #$05,D0
    beq.s  __far_z_01_0016
    jmp  L6104_Exit
__far_z_01_0016:
    ; Advance the teleporting index, and store the mask for its level in [00].
    ;
    jsr     AdvanceTeleportingLevelIndex
    move.b  ($0523,A4),D0
    andi.b #$07,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (LevelMasks).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0000,A4)
    even
_L_z01_SummonWhirlwind_LoopTriforcePiece:
    ; If there are no triforce pieces, then return.
    ;
    move.b  ($0671,A4),D0
    bne.s  __far_z_01_0017
    jmp  L6104_Exit
__far_z_01_0017:
    ; If we have gotten this triforce piece, then go try to make a
    ; whirlwind.
    ;
    move.b  ($0000,A4),D1
    and.b   D0,D1   ; BIT: set Z/N/V from D1 AND A
    bne  _L_z01_SummonWhirlwind_MakeWhirlwind
    ; We have not gotten this piece.
    ; First, advance the teleporting index again.
    ;
    jsr     AdvanceTeleportingLevelIndex
    ; If the direction Link is facing is an increasing one, then
    ; rotate the level mask in [00] left to correspond to the higher
    ; level number. Then go test this new mask.
    ;
    move.b  ($0098,A4),D0
    andi.b #$09,D0
    beq  _L_z01_SummonWhirlwind_DecreasingDir
    move.b  ($0000,A4),D1
    lsl.b  #1,D1   ; ASL $00
    move.b  D1,($0000,A4)
    bcc  _L_z01_SummonWhirlwind_LoopTriforcePiece
    move.b  ($0000,A4),D1
    roxl.b  #1,D1   ; ROL $00
    move.b  D1,($0000,A4)
    jmp     _L_z01_SummonWhirlwind_LoopTriforcePiece

    even
_L_z01_SummonWhirlwind_DecreasingDir:
    ; If instead the direction is a decreasing one, then
    ; rotate right to correspond to the lower level number.
    ; Then go test this new mask.
    ;
    move.b  ($0000,A4),D1
    lsr.b  #1,D1   ; LSR $00
    move.b  D1,($0000,A4)
    bcc  _L_z01_SummonWhirlwind_LoopTriforcePiece
    move.b  ($0000,A4),D1
    roxr.b  #1,D1   ; ROR $00
    move.b  D1,($0000,A4)
    jmp     _L_z01_SummonWhirlwind_LoopTriforcePiece

    even
_L_z01_SummonWhirlwind_MakeWhirlwind:
    ; If already summoned or in the middle of teleporting, then
    ; return and don't summon another one.
    ;
    move.b  ($0508,A4),D0
    move.b  ($0522,A4),D1
    or.b  D1,D0
    beq.s  __far_z_01_0018
    jmp  L6104_Exit
__far_z_01_0018:
    ; Return if we can't find an empty monster slot.
    ;
    jsr     FindEmptyMonsterSlot
    bne.s  __far_z_01_0019
    jmp  L6104_Exit
__far_z_01_0019:
    ; An empty slot was found. Flag that summoned the whirlwind.
    ; Switch to the empty slot, and go set up a whirlwind object.
    ;
    addq.b  #1,($0508,A4)
    move.b  D3,D0
    moveq   #0,D2
    move.b  D0,D2
    jmp     SetUpWhirlwind

    even
AdvanceTeleportingLevelIndex:
    ; If Link is facing an increasing direction (right or down), then
    ; increase the index. Otherwise, decrease it.
    ;
    addq.b  #1,($0523,A4)
    move.b  ($0098,A4),D0
    andi.b #$09,D0
    beq.s  __far_z_01_0020
    jmp  L6104_Exit
__far_z_01_0020:
    subq.b  #1,($0523,A4)
    subq.b  #1,($0523,A4)
    even
L6104_Exit:
    rts

    even
DrawWhirlwind:
    ; Frames last 1 screen frame.
    ;
    moveq   #1,D0
    jsr     Anim_AdvanceAnimCounterAndSetObjPosForSpriteDescriptor
    ; The whirlwind flashes by using a palette row based on the
    ; screen frame counter.
    ;
    move.b  ($0015,A4),D0
    andi.b #$03,D0
    jsr     Anim_SetSpriteDescriptorAttributes
    ; Flip horizontally based on movement frame, which is
    ; switched based on animation counter.
    ;
    jsr     Anim_SetObjHFlipForSpriteDescriptor
    moveq   #0,D0
    jmp     DrawObjectNotMirrored

    even
TeleportYs:
    dc.b    $8D, $AD, $8D, $8D, $AD, $8D, $AD, $5D

    even
CheckInitWhirlwindAndBeginUpdate:
    move.b  ($0522,A4),D0
    beq  _anon_z01_21
    ; Since we're already teleporting, the source room was
    ; already done. Set up the whirlwind object in destination room.
    ;
    ; Teleporting state 2 drops off Link.
    ;
    addq.b  #1,($0522,A4)
    moveq   #64,D0
    move.b  D0,($00AC,A4)
    moveq   #9,D2
    move.b  ($0523,A4),D0
    andi.b #$07,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     (TeleportYs).l,A0
    move.b  (A0,D3.W),D0
    jsr     InitWhirlwind
_anon_z01_21:
    jmp     BeginUpdateMode

; Params:
; [0F]: movement direction
;
; Returns:
; [0F]: untouched, or 0
;
;
; Look for a tile object among objects 1 to 12 that can block
; the player's movement.
;
    even
CheckTileObjectsBlocking:
    moveq   #12,D2
    even
_L_z01_CheckTileObjectsBlocking_LoopTileObj:
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$68,D0
    beq  _L_z01_CheckTileObjectsBlocking_Found
    cmpi.b  #$62,D0
    beq  _L_z01_CheckTileObjectsBlocking_Found
    cmpi.b  #$65,D0
    beq  _L_z01_CheckTileObjectsBlocking_Found
    cmpi.b  #$66,D0
    bne  _L_z01_CheckTileObjectsBlocking_NextTileObj
    even
_L_z01_CheckTileObjectsBlocking_Found:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$01,D0
    bne  _L_z01_CheckTileObjectsBlocking_NextTileObj
    ; If X distance between Link and the object >= $10, skip it.
    ;
    move.b  ($0070,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
; [SBC unhandled mode=ABS_X] SBC ObjX, X
    jsr     Abs
    cmpi.b  #$10,D0
    bcc  _L_z01_CheckTileObjectsBlocking_NextTileObj
    ; If Y distance between Link and the object >= $10, skip it.
    ;
    move.b  ($0084,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$03,D1
    addx.b  D1,D0   ; ADC #$03 (X flag = 6502 C)
    ori     #$11,CCR  ; SEC: set C+X
; [SBC unhandled mode=ABS_X] SBC ObjY, X
    jsr     Abs
    cmpi.b  #$10,D0
    bcc  _L_z01_CheckTileObjectsBlocking_NextTileObj
    ; Link is near the object. Reset movement direction.
    ;
    moveq   #0,D0
    move.b  D0,($000F,A4)
    even
_L_z01_CheckTileObjectsBlocking_NextTileObj:
    subq.b  #1,D2
    bne  _L_z01_CheckTileObjectsBlocking_LoopTileObj
    rts

    even
CheckPowerTriforceFanfare:
    ; If the fanfare is not active, then return.
    ;
    move.b  ($0509,A4),D0
    beq  _L_z01_CheckPowerTriforceFanfare_Exit
    ; When Link's timer expires, go finish up the fanfare.
    ;
    move.b  ($0028,A4),D0
    beq  _L_z01_CheckPowerTriforceFanfare_EndFanfare
    ; While Link's timer is counting down, every 4 frames, switch
    ; between the level palette and the white palette.
    ;
    moveq   #24,D3
    ; Redundant check of Link's timer that won't branch.
    ;
    move.b  ($0028,A4),D0
    beq  _L_z01_CheckPowerTriforceFanfare_FillHearts
    andi.b #$07,D0
    cmpi.b  #$04,D0
    bcs  _anon_z01_22
    moveq   #120,D3
_anon_z01_22:
    move.b  D3,($0014,A4)
    rts

    even
_L_z01_CheckPowerTriforceFanfare_FillHearts:
    moveq   #2,D0
    move.b  D0,($0063,A4)
    addq.b  #1,($0013,A4)
    rts

    even
_L_z01_CheckPowerTriforceFanfare_EndFanfare:
    ; The fanfare is done.
    ;
    jsr     ReplaceAshesPaletteRow
    moveq   #32,D0
    move.b  D0,($0600,A4)
    moveq   #1,D0
    move.b  D0,($0672,A4)
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($00AC,A4)
    move.b  D0,($0509,A4)
    even
_L_z01_CheckPowerTriforceFanfare_Exit:
    rts

    even
TakePowerTriforce:
    addq.b  #1,($0509,A4)
    ; Halt Link for $C0 frames.
    ;
    move.b  #$C0,D0
    move.b  D0,($0028,A4)
    moveq   #64,D0
    move.b  D0,($00AC,A4)
    rts

    even
PaletteRow7TransferRecord:
    dc.b    $3F, $1C, $04, $0F, $07, $17, $27, $FF

; First: Ganon brown state
; Second: Ganon blue state
; Third: Ashes and Triforce
;
    even
GanonColorTriples:
    dc.b    $07, $17, $30, $16, $2C, $3C, $27, $06
    dc.b    $16

    even
ReplaceGanonBrownPaletteRow:
    moveq   #2,D3
    bne  _anon_z01_23
    even
ReplaceGanonBluePaletteRow:
    moveq   #5,D3
    bne  _anon_z01_23
    even
ReplaceAshesPaletteRow:
    moveq   #8,D3
_anon_z01_23:
    move.b  D3,D0
    move.b  D0,-(A5)  ; PHA
    ; Get the dynamic transfer buf length, so we write from were we last wrote.
    ;
    moveq   #0,D2
    move.b  ($0301,A4),D2
    ; Copy the palette row 7 transfer record to dynamic transfer buf (8 bytes).
    ;
    moveq   #0,D3
    even
_L_z01_ReplaceAshesPaletteRow_CopyPaletteRecord:
    lea     (PaletteRow7TransferRecord).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D2
    addq.b  #1,D3
    cmpi.b  #$08,D3
    bne  _L_z01_ReplaceAshesPaletteRow_CopyPaletteRecord
    ; Update the dynamic transfer buf length.
    ;
    move.b  D2,($0301,A4)
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    ; Replace the last 3 color bytes (brown shades) that we just
    ; copied to the dynamic transfer buf with the colors of the
    ; pile of ashes.
    ;
    ; Note that here the dynamic transfer buf is being written with
    ; absolute offsets, instead of relative ones used in copying
    ; the base/template palette row transfer record.
    ;
    moveq   #2,D2
    even
_L_z01_ReplaceAshesPaletteRow_ReplaceColors:
    lea     (GanonColorTriples).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0306,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D3
    subq.b  #1,D2
    bpl  _L_z01_ReplaceAshesPaletteRow_ReplaceColors
    ; Switch back to the current object slot.
    ;
    moveq   #0,D2
    move.b  ($0340,A4),D2
    rts

; Unknown block
    dc.b    $20, $93, $FA, $A9, $0B, $4C, $DF, $77
    dc.b    $A5, $BF, $F0, $0E, $20, $14, $73, $D0
    dc.b    $09, $A9, $00, $85, $BF, $A9, $02, $8D
    dc.b    $02, $06, $60

    even
LinkToSquareOffsetsX:
    dc.b    $00, $00, $F0, $10

    even
LinkToSquareOffsetsY:
    dc.b    $FB, $13, $03, $03

; Returns:
; X: 0
;
;
; If grid offset <> 0 or input direction = 0, return.
;
    even
CheckPassiveTileObjects:
    move.b  ($0394,A4),D0
    bne  _L_z01_CheckPassiveTileObjects_ReturnX0
    move.b  ($03F8,A4),D0
    beq  _L_z01_CheckPassiveTileObjects_ReturnX0
    ; Compare the collided tile with tiles $BC to $C3.
    ; These are tiles for gravestone and armos squares.
    ;
    move.b  #$BB,D0
    move.b  D0,($0002,A4)
    moveq   #8,D2
    move.b  ($049E,A4),D0
    even
_L_z01_CheckPassiveTileObjects_NextTile:
    addq.b  #1,($0002,A4)
    subq.b  #1,D2
    bpl  _L_z01_CheckPassiveTileObjects_TestTile
    even
_L_z01_CheckPassiveTileObjects_ReturnX0:
    moveq   #0,D2
    rts

    even
_L_z01_CheckPassiveTileObjects_TestTile:
    move.b  ($0002,A4),D1
    cmp.b   D1,D0
    bne  _L_z01_CheckPassiveTileObjects_NextTile
    ; We'll be computing the location of the square.
    ; Start with Link's location.
    ;
    move.b  ($0070,A4),D0
    move.b  D0,($0000,A4)
    move.b  ($0084,A4),D0
    move.b  D0,($0001,A4)
    move.b  ($0098,A4),D0
    andi.b #$0C,D0
    beq  _L_z01_CheckPassiveTileObjects_CheckHorizontal
    ; Link is facing vertically.
    ;
    ; If Link touched the left side of the square with the right side
    ; of his body, then add 8 to X.
    ;
    ; If Link touched the right side of the square with the left side
    ; of his body, then bitwise AND'ing with $F0 will align X with the square.
    ;
    move.b  ($0002,A4),D0
    andi.b #$03,D0
    moveq   #0,D3
    move.b  D0,D3
    move.b  ($0000,A4),D0
    cmpi.b  #$02,D3
    bcc  _anon_z01_24
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
_anon_z01_24:
    andi.b #$F0,D0
    move.b  D0,($0000,A4)
    jmp     _L_z01_CheckPassiveTileObjects_FindSlot

    even
_L_z01_CheckPassiveTileObjects_CheckHorizontal:
    ; Link is facing horizontally.
    ;
    ; If Link touched the top of the square with the bottom
    ; of his body, then add 8 to Y.
    ;
    move.b  ($0002,A4),D0
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z01_CheckPassiveTileObjects_FindSlot
    move.b  ($0001,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0001,A4)
    even
_L_z01_CheckPassiveTileObjects_FindSlot:
    ; Look for an empty slot to instantiate a monster in.
    ; If none was found, then return.
    ;
    jsr     FindEmptyMonsterSlot
    beq  _L_z01_CheckPassiveTileObjects_ExitX0
    ; When dealing with objects, X usually indicates the slot number
    ; of the object. Set it to the empty slot found.
    ;
    moveq   #0,D2
    move.b  ($0059,A4),D2
    ; Offset the coordinates we calculated by a square length
    ; in the direction Link is facing.
    ;
    ; Set the new object's location to them.
    ;
    move.b  ($0098,A4),D0
    jsr     GetOppositeDir
    move.b  ($0000,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (LinkToSquareOffsetsX).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC LinkToSquareOffsetsX,Y
    move.b  D0,($70,A4,D2.W)
    move.b  ($0001,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     (LinkToSquareOffsetsY).l,A0
    move.b  (A0,D3.W),D1
    addx.b  D1,D0   ; ADC LinkToSquareOffsetsY,Y
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    ; Return, if the empty slot we found indicates it was initialized.
    ; I don't know how it would get in this state, because when
    ; a monster is destroyed, type is assigned 0, and it's uninitialized.
    ;
    lea     ($0492,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z01_CheckPassiveTileObjects_ExitX0
    ; Because armos and flying ghini fade into existence over a little time,
    ; see if one is already beginning to appear at that location.
    ; Don't instantiate another one, if there is.
    ;
    moveq   #11,D3
    move.b  D2,($0003,A4)
    even
_L_z01_CheckPassiveTileObjects_FindObjAtLocation:
    move.b  ($0003,A4),D1
    cmp.b   D1,D3
    beq  _L_z01_CheckPassiveTileObjects_NextObjAtLocation
    move.b  ($70,A4,D3.W),D0
    move.b  ($70,A4,D2.W),D1
    cmp.b   D1,D0
    bne  _L_z01_CheckPassiveTileObjects_NextObjAtLocation
    lea     ($0084,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    bne  _L_z01_CheckPassiveTileObjects_NextObjAtLocation
    lea     ($034F,A4),A0
    move.b  (A0,D3.W),D0
    bne  _L_z01_CheckPassiveTileObjects_ExitX0
    lea     ($0492,A4),A0
    move.b  (A0,D3.W),D0
    beq  _L_z01_CheckPassiveTileObjects_ExitX0
    bne  _L_z01_CheckPassiveTileObjects_ChooseObjType
    even
_L_z01_CheckPassiveTileObjects_NextObjAtLocation:
    subq.b  #1,D3
    bne  _L_z01_CheckPassiveTileObjects_FindObjAtLocation
    even
_L_z01_CheckPassiveTileObjects_ChooseObjType:
    ; Choose the right object type for the tile.
    ;
    ;
    ; Armos
    moveq   #30,D0
    moveq   #0,D3
    move.b  ($0002,A4),D3
    cmpi.b  #$C0,D3
    bcc  _anon_z01_25
    moveq   #34,D0
_anon_z01_25:
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     ResetObjMetastate
    moveq   #63,D0
    move.b  D0,($28,A4,D2.W)
    even
_L_z01_CheckPassiveTileObjects_ExitX0:
    moveq   #0,D2
    rts

    even
RupeeStashXs:
    dc.b    $78, $70, $80, $60, $70, $80, $90, $70
    dc.b    $80, $78

    even
RupeeStashYs:
    dc.b    $70, $80, $80, $90, $90, $90, $90, $A0
    dc.b    $A0, $B0

    even
InitRupeeStash_Full:
    ; When initializing, this object makes other objects that
    ; each have the same object attributes and type as this one.
    ;
    lea     ($04BF,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
    moveq   #53,D0
    move.b  D0,($0000,A4)
    ; Loop over $A rupee stash objects to make
    ; -- each one now representing an individual rupee
    ;
    moveq   #10,D2
    even
_L_z01_InitRupeeStash_Full_LoopRupee:
    jsr     InitOneSimpleObject
    ; Look up and set the coordinates for one rupee stash/rupee.
    ;
    lea     (RupeeStashXs-1).l,A0
    move.b  (A0,D2.W),D0
    move.b  D0,($70,A4,D2.W)
    lea     (RupeeStashYs-1).l,A0
    move.b  (A0,D2.W),D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    subq.b  #1,D2
    bne  _L_z01_InitRupeeStash_Full_LoopRupee
    rts

; Params:
; [00]: object type
; [01]: object attributes
;
    even
InitOneSimpleObject:
    move.b  ($0000,A4),D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #0,D0
    lea     ($0492,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  ($0001,A4),D0
    lea     ($04BF,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
TrapXs:
    dc.b    $20, $20, $D0, $D0, $40, $B0

    even
TrapYs:
    dc.b    $5D, $BD, $5D, $BD, $8D, $8D

    even
InitTrap_Full:
    ; Copy this parent/generator object's attributes to [01].
    ;
    lea     ($04BF,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0001,A4)
    ; Assume we're initializing trap object type $49 that makes 6 traps.
    ;
    moveq   #5,D3
    ; The individual trap objects to make will be of type $49.
    ; Store it in [00].
    ;
    moveq   #73,D0
    move.b  D0,($0000,A4)
    ; If the object type we're initializing is not $49 (as in it's $4A),
    ; then we'll make 4 traps.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq  _L_z01_InitTrap_Full_LoopTrap
    moveq   #3,D3
    even
_L_z01_InitTrap_Full_LoopTrap:
    ; Loop over each trap to make, from the last index (5 or 3) to 0.
    ;
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    ; Add the loop index to the current object slot, and switch the X register to it.
    ;
    move.b  ($0340,A4),D1
    addx.b  D1,D0   ; ADC CurObjIndex
    moveq   #0,D2
    move.b  D0,D2
    ; Look up and set the location for this iteration's individual trap.
    ;
    lea     (TrapXs).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,($70,A4,D2.W)
    lea     (TrapYs).l,A0
    move.b  (A0,D3.W),D0
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     InitOneSimpleObject
    subq.b  #1,D2
    subq.b  #1,D3
    bpl  _L_z01_InitTrap_Full_LoopTrap
    rts

    even
TrapAllowedDirs:
    dc.b    $05, $09, $06, $0A, $01, $02

    even
UpdateTrap_Full:
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z01_UpdateTrap_Full_UpdateMovingStates
    ; State 0. Sensing.
    ;
    ; If the absolute vertical distance between Link and the trap >= $E,
    ; then go see if the horizontal distance is shorter.
    ;
    move.b  ($0084,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
; [SBC unhandled mode=ABS_X] SBC ObjY, X
    jsr     Abs
    cmpi.b  #$0E,D0
    bcc  _L_z01_UpdateTrap_Full_CheckHorizontal
    ; Determine the horizontal direction toward Link;
    ; and if Link and the trap are at the same X, then we can't move
    ; along this axis. Go see about moving vertically.
    ;
    moveq   #1,D3
    move.b  ($0070,A4),D0
    move.b  ($70,A4,D2.W),D1
    cmp.b   D1,D0
    beq  _L_z01_UpdateTrap_Full_CheckHorizontal
    bcs  _anon_z01_26
    moveq   #2,D3
_anon_z01_26:
    ; Remember the original X coordinate.
    ;
    move.b  ($70,A4,D2.W),D0
    even
_L_z01_UpdateTrap_Full_GoToState1:
    lea     ($0380,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set facing direction to the horizontal one that we determined.
    ;
    move.b  D3,D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; If the direction we determined is not allowed for this trap, then
    ; go draw and check collisions.
    ;
    lea     (TrapAllowedDirs-1).l,A0
    move.b  (A0,D2.W),D1
    and.b  D1,D0
    beq  _L_z01_UpdateTrap_Full_DrawAndCheckCollisions
    ; Advance to state 1 with q-speed $70 (1.75 pixels a frame) (fast).
    ;
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    moveq   #112,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z01_UpdateTrap_Full_DrawAndCheckCollisions:
    jmp     L_Trap_DrawAndCheckCollisions

    even
_L_z01_UpdateTrap_Full_CheckHorizontal:
    ; If the horizontal distance between Link and the trap >= $E,
    ; then this trap definitely wasn't triggered.
    ; Go draw and check collisions.
    ;
    move.b  ($0070,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
; [SBC unhandled mode=ABS_X] SBC ObjX, X
    jsr     Abs
    cmpi.b  #$0E,D0
    bcc  _L_z01_UpdateTrap_Full_DrawAndCheckCollisions
    ; Determine the vertical direction toward Link;
    ; and if Link and the trap are at the same Y, then we can't move
    ; along this axis. Go draw and check object collisions.
    ;
    moveq   #4,D3
    move.b  ($0084,A4),D0
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq  _L_z01_UpdateTrap_Full_DrawAndCheckCollisions
    bcs  _anon_z01_27
    moveq   #8,D3
_anon_z01_27:
    ; We'll advance to state 1. Go remember the original Y coordinate,
    ; set the vertical direction we determined, and other preparations.
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z01_UpdateTrap_Full_GoToState1
    even
_L_z01_UpdateTrap_Full_UpdateMovingStates:
    ; State 1 and 2.
    ;
    ; Move in the direction it's facing.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($000F,A4)
    jsr     MoveObject
    ; Truncate the grid offset to square length ($10).
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0F,D0
    bne  _anon_z01_28
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
_anon_z01_28:
    ; The trap cannot be harmed. So, only check for collision with Link.
    ;
    jsr     CheckLinkCollision
    ; If moving horizontally, then set target coordinate in [00] to $78
    ; and current coordinate to the trap's X.
    ;
    moveq   #0,D3
    move.b  ($70,A4,D2.W),D3
    moveq   #120,D0
    move.b  D0,($0000,A4)
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$0C,D0
    beq  _L_z01_UpdateTrap_Full_Finish
    ; Else moving vertically. Set target coordinate in [00] to $90
    ; and current coordinate to the trap's Y.
    ;
    moveq   #0,D3
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D3
    move.b  #$90,D0
    move.b  D0,($0000,A4)
    even
_L_z01_UpdateTrap_Full_Finish:
    ; If in state 2, then go finish handling it.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$01,D0
    beq  _L_z01_UpdateTrap_Full_FinishState2
    ; Finish handling state 1.
    ;
    ; Get the distance between the current coordinate and the target.
    ;
    move.b  D3,D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0000,A4),D1
    subx.b  D1,D0   ; SBC $00
    jsr     Abs
    ; If distance >= 5, go draw.
    ;
    cmpi.b  #$05,D0
    bcc  _L_z01_UpdateTrap_Full_Draw
    ; Else reverse direction, and advace to state 2
    ; with q-speed $20 (0.5 pixels a frame) (slow).
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    jsr     GetOppositeDir
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #32,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($00AC,A4),A0
    addq.b  #1,(A0,D2.W)
    even
_L_z01_UpdateTrap_Full_Draw:
    jmp     L_Trap_DrawAndCheckCollisions

    even
_L_z01_UpdateTrap_Full_FinishState2:
    ; Finish handling state 2.
    ;
    ; If the current coordinate = original coordinate, then go to state 0.
    ;
    move.b  D3,D0
    lea     ($0380,A4),A0
    move.b  (A0,D2.W),D1
    cmp.b   D1,D0
    beq.s  __far_z_01_0021
    jmp  L_Trap_DrawAndCheckCollisions
__far_z_01_0021:
    moveq   #0,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
L_Trap_DrawAndCheckCollisions:
    jmp     Person_DrawAndCheckCollisions_Common

    even
UpdateRupeeStash_Full:
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    ; If Link is not close enough (< 9 pixels in both axes), then
    ; go draw.
    ;
    move.b  ($0084,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
; [SBC unhandled mode=ABS_X] SBC ObjY, X
    jsr     Abs
    cmpi.b  #$09,D0
    bcc  _L_z01_UpdateRupeeStash_Full_DrawRupee
    move.b  ($0070,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
; [SBC unhandled mode=ABS_X] SBC ObjX, X
    jsr     Abs
    cmpi.b  #$09,D0
    bcc  _L_z01_UpdateRupeeStash_Full_DrawRupee
    ; Else Link is close enough. Add 1 rupee, and destroy this object.
    ;
    jsr     TakeOneRupee
    jsr     DestroyMonster
    ; Once you've taken one, it counts as taking them all
    ; once you leave the room.
    ;
    moveq   #0,D0
    move.b  D0,($034E,A4)
    jmp     _L_z01_UpdateRupeeStash_Full_ExitRestoreX

    even
_L_z01_UpdateRupeeStash_Full_DrawRupee:
    ; Draw a rupee.
    ;
    jsr     Anim_FetchObjPosForSpriteDescriptor
    moveq   #22,D2
    moveq   #22,D3
    jsr     DrawItemInInventory
    even
_L_z01_UpdateRupeeStash_Full_ExitRestoreX:
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    rts

; Unknown block
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
    dc.b    $FF, $FF, $FF, $FF, $FF, $FF, $FF, $FF
