; Formats a decimal byte. Spaces are used for missing digits.
;
; Params:
; A: value
;
; Returns:
; Y: First character
; A: Second character
; [$01]: First character
; [$02]: Second character
; [$03]: Third character
;
    even
FormatDecimalByte:
    jsr     DivideBy10
    move.b  D0,($0003,A4)
    move.b  D3,D0
    jsr     DivideBy10
    cmpi.b  #$00,D3
    bne  _L_z01_FormatDecimalByte_WriteHighChars
    moveq   #36,D3
    cmpi.b  #$00,D0
    bne  _L_z01_FormatDecimalByte_WriteHighChars
    move.b  D3,D0
    even
_L_z01_FormatDecimalByte_WriteHighChars:
    move.b  D0,($0002,A4)
    move.b  D3,($0001,A4)
_anon_z01_41:
    rts

; Params:
; A: value
;
; Returns:
; Y: result
; A: remainder
;
    even
DivideBy10:
    moveq   #0,D3
    even
_L_z01_DivideBy10_Loop:
    cmpi.b  #$0A,D0
    bcs  _anon_z01_41
    move.b  #$0A,D1
    subx.b  D1,D0   ; SBC #$0A
    addq.b  #1,D3
    bne  _L_z01_DivideBy10_Loop
    even
FormatHeartsInTextBuf:
    ; [$0E]: hearts value
    ; [$0F]: heart partial
    ; Y: The offset of first character in buffer
    ;
    ; The end of the bottom row is $12 bytes after the
    ; start of the top row. We're writing to two transfer
    ; records. We write the top row in the first transfer
    ; record wherever the caller chooses. The second
    ; transfer record has to begin with the heart tiles.
    ; So, 7 (offset to end of first row) + 3 (size of transfer
    ; header) + 8 (length of bottom row) = 18 ($12).
    ;
    ; Store the starting offset in [$0D].
    move.b  D3,($000D,A4)
    move.b  ($000E,A4),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$0F,D0
    move.b  D0,($0000,A4)
    moveq   #15,D0                    ; PATCH P36d: exact $0F-$00, no SUBX off-by-one
    move.b  ($0000,A4),D1
    sub.b   D1,D0
    move.b  D0,($0000,A4)
    move.b  (A5)+,D0  ; PLA
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    move.b  D0,($0001,A4)
    moveq   #15,D0                    ; PATCH P36d: exact $0F-$01, no SUBX off-by-one
    move.b  ($0001,A4),D1
    sub.b   D1,D0
    move.b  D0,($0001,A4)
    ; At this point,
    ; [$00] = $F - hearts
    ; [$01] = $F - heart containers
    ; [$0D] = Y parameter (starting offset in tile buf)
    ;
    ; Also, Y is still set to the value passed in.
    ;
    moveq   #0,D2
    move.b  D3,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$07,D1
    addx.b  D1,D0   ; ADC #$07 (X flag = 6502 C)
    move.b  D0,($000B,A4)
    ; Y keeps track of index of heart in row.
    ; Start at the end of the first row.
    moveq   #7,D3
    even
_L_z01_FormatHeartsInTextBuf_LoopHeartSlot:
    ; For X in 0..$10 (all hearts spots):
    ;
    cmpi.b  #$FF,D3
    bne  _L_z01_FormatHeartsInTextBuf_FinishedFirstRow
    move.b  ($000D,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$12,D1
    addx.b  D1,D0   ; ADC #$12 (X flag = 6502 C)
    move.b  D0,($000B,A4)
    moveq   #18,D3
    even
_L_z01_FormatHeartsInTextBuf_FinishedFirstRow:
    ; If there are no hearts,
    ; or still processing missing heart containers;
    move.b  ($000E,A4),D0
    beq  _L_z01_FormatHeartsInTextBuf_EmitSpace
    move.b  ($0001,A4),D1
    cmp.b   D1,D2
    bcc  _L_z01_FormatHeartsInTextBuf_CheckOccupiedSlot
    even
_L_z01_FormatHeartsInTextBuf_EmitSpace:
    moveq   #36,D0
    bne  _L_z01_FormatHeartsInTextBuf_EmitChar
    even
_L_z01_FormatHeartsInTextBuf_CheckOccupiedSlot:
    move.b  ($0000,A4),D1
    cmp.b   D1,D2
    beq  _L_z01_FormatHeartsInTextBuf_CheckPartial
    bcs  _L_z01_FormatHeartsInTextBuf_EmitEmptyHeart   ; PATCH P36c: 68K borrow sense for CPX/BCC
    even
_L_z01_FormatHeartsInTextBuf_EmitFullHeart:
    move.b  #$F2,D0
    bne  _L_z01_FormatHeartsInTextBuf_EmitChar
    even
_L_z01_FormatHeartsInTextBuf_CheckPartial:
    move.b  ($000F,A4),D0
    beq  _L_z01_FormatHeartsInTextBuf_EmitEmptyHeart
    cmpi.b  #$80,D0
    bcc  _L_z01_FormatHeartsInTextBuf_EmitFullHeart
    moveq   #0,D0
    move.b  D0,($0529,A4)
    moveq   #101,D0
    bne  _L_z01_FormatHeartsInTextBuf_EmitChar
    even
_L_z01_FormatHeartsInTextBuf_EmitEmptyHeart:
    moveq   #102,D0
    even
_L_z01_FormatHeartsInTextBuf_EmitChar:
    move.b  D3,($000C,A4)
    moveq   #0,D3
    move.b  ($000B,A4),D3
    lea     ($0302,A4),A0
    move.b  D0,(A0,D3.W)
    subq.b  #1,($000B,A4)
    moveq   #0,D3
    move.b  ($000C,A4),D3
    subq.b  #1,D3
    addq.b  #1,D2
    cmpi.b  #$10,D2
    bne  _L_z01_FormatHeartsInTextBuf_LoopHeartSlot
    rts

