; Params:
; X: object index
; [0F]: direction
;
; Returns:
; Y: direction of boundary that was crossed
; [0F]: original direction, or 0 if boundary was crossed
;
;
; Checking left direction.
    even
BoundDirectionHorizontally:
    moveq   #2,D3
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0000,A4)
    cmpi.b  #$00,D2
    beq  _L_z01_BoundDirectionHorizontally_Left
    ; If object slot >= $D (items and weapons) or object type = $5C (boomerang),
    ; then add $B to X coordinate.
    ;
    cmpi.b  #$0D,D2
    bcc  _anon_z01_43
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$5C,D0
    bne  _L_z01_BoundDirectionHorizontally_Left
_anon_z01_43:
    move.b  ($0000,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$0B,D1
    addx.b  D1,D0   ; ADC #$0B (X flag = 6502 C)
    move.b  D0,($0000,A4)
    even
_L_z01_BoundDirectionHorizontally_Left:
    ; Check left boundary.
    ; If X coordinate crosses (<) left bound, go reset the direction.
    ;
    move.b  ($0000,A4),D0
    move.b  ($0346,A4),D1
    cmp.b   D1,D0
    bcc.s  __far_z_01_0026
    jmp  BoundDirectionReturn
__far_z_01_0026:
    ; If object is not the player and (slot >= $D or type = $5C),
    ; then subtract $17 from X coordinate in order to check the
    ; right bound.
    ;
    cmpi.b  #$00,D2
    beq  _L_z01_BoundDirectionHorizontally_Right
    cmpi.b  #$0D,D2
    bcc  _anon_z01_44
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$5C,D0
    bne  _L_z01_BoundDirectionHorizontally_Right
_anon_z01_44:
    move.b  ($0000,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$17,D1
    subx.b  D1,D0   ; SBC #$17
    move.b  D0,($0000,A4)
    even
_L_z01_BoundDirectionHorizontally_Right:
    ; Check right boundary.
    ; If X coordinate is within (<) right bound, return and leave direction alone.
    ;
    moveq   #1,D3
    move.b  ($0000,A4),D0
    move.b  ($0347,A4),D1
    cmp.b   D1,D0
    bcc.s  __far_z_01_0027
    jmp  L6825_Exit
__far_z_01_0027:
    even
BoundDirectionReturn:
    ; If the reference direction in Y register is 0, then
    ; return and leave direction alone.
    ; Else reset the target direction.
    ;
    move.b  D3,D0
    move.b  ($000F,A4),D1
    and.b  D1,D0
    bne.s  __far_z_01_0028
    jmp  L6825_Exit
__far_z_01_0028:
    jmp     ResetMovingDir

; Params:
; X: object index
; [0F]: direction
;
; Returns:
; Y: direction of boundary that was crossed
; [0F]: original direction, or 0 if boundary was crossed
;
;
; Checking up direction.
    even
BoundDirectionVertically:
    moveq   #8,D3
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0000,A4)
    cmpi.b  #$00,D2
    beq  _L_z01_BoundDirectionVertically_Up
    ; If object slot >= $D (items and weapons) or object type = $5C (boomerang),
    ; then add $F to X coordinate.
    ;
    cmpi.b  #$0D,D2
    bcc  _anon_z01_45
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$5C,D0
    bne  _L_z01_BoundDirectionVertically_Up
_anon_z01_45:
    move.b  ($0000,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$0F,D1
    addx.b  D1,D0   ; ADC #$0F (X flag = 6502 C)
    move.b  D0,($0000,A4)
    even
_L_z01_BoundDirectionVertically_Up:
    ; Check up boundary.
    ; If Y coordinate crosses (<) up bound, go reset the direction.
    ;
    move.b  ($0000,A4),D0
    move.b  ($0348,A4),D1
    cmp.b   D1,D0
    bcc.s  __far_z_01_0029
    jmp  BoundDirectionReturn
__far_z_01_0029:
    ; If object is not the player and (slot >= $D or type = $5C),
    ; then subtract $21 from Y coordinate in order to check the
    ; down bound.
    ;
    cmpi.b  #$00,D2
    beq  _L_z01_BoundDirectionVertically_Down
    cmpi.b  #$0D,D2
    bcc  _anon_z01_46
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$5C,D0
    bne  _L_z01_BoundDirectionVertically_Down
_anon_z01_46:
    move.b  ($0000,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  #$21,D1
    subx.b  D1,D0   ; SBC #$21
    move.b  D0,($0000,A4)
    even
_L_z01_BoundDirectionVertically_Down:
    ; Check down boundary.
    ; If Y coordinate is within (<) down bound, return and leave direction alone.
    ;
    moveq   #4,D3
    move.b  ($0000,A4),D0
    move.b  ($0349,A4),D1
    cmp.b   D1,D0
    bcs.s  __far_z_01_0030
    jmp  BoundDirectionReturn
__far_z_01_0030:
    even
L6825_Exit:
