; Params:
; [010E]: PositiveGridCellSize
; [010F]: NegativeGridCellSize
;
; Returns:
; C: 1 if fractional position reached a whole pixel
;
    even
AddQSpeedToPositionFraction:
    lea     ($03A8,A4),A0
    move.b  (A0,D2.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($03BC,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjQSpeedFrac,X
    lea     ($03A8,A4),A0
    move.b  D0,(A0,D2.W)
    move.w  SR,D1
    move.b  D1,-(A5)  ; PHP: push CCR
    ; Don't let positions go past the limits
    ; If we're at a limit, then clear carry.
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($010E,A4),D1
    cmp.b   D1,D0
    beq  _L_z01_AddQSpeedToPositionFraction_ClearCarry
    move.b  ($010F,A4),D1
    cmp.b   D1,D0
    bne  _anon_z01_47
    even
_L_z01_AddQSpeedToPositionFraction_ClearCarry:
    move.b  (A5)+,D1  ; PLP: pop to CCR
    move.w  D1,CCR
    andi    #$EE,CCR  ; CLC: clear C+X
    move.w  SR,D1
    move.b  D1,-(A5)  ; PHP: push CCR
_anon_z01_47:
    move.b  (A5)+,D1  ; PLP: pop to CCR
    move.w  D1,CCR
    move.w  SR,D1
    move.b  D1,-(A5)  ; PHP: push CCR
    ; Add only carry to the grid offset.
    ; Carry represents whether the fractional position reached
    ; a whole pixel (C=1).
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$00,D1
    addx.b  D1,D0   ; ADC #$00 (X flag = 6502 C)
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D1  ; PLP: pop to CCR
    move.w  D1,CCR
    rts

; Params:
; [010E]: PositiveGridCellSize
; [010F]: NegativeGridCellSize
;
; Returns:
; C: 0 if fractional position reached a whole pixel
;
    even
SubQSpeedFromPositionFraction:
    lea     ($03A8,A4),A0
    move.b  (A0,D2.W),D0
    ori     #$11,CCR  ; SEC: set C+X
; [SBC unhandled mode=ABS_X] SBC ObjQSpeedFrac, X
    lea     ($03A8,A4),A0
    move.b  D0,(A0,D2.W)
    move.w  SR,D1
    move.b  D1,-(A5)  ; PHP: push CCR
    ; Don't let positions go past the limits
    ; If we're at a limit, then set carry.
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($010E,A4),D1
    cmp.b   D1,D0
    beq  _L_z01_SubQSpeedFromPositionFraction_SetCarry
    move.b  ($010F,A4),D1
    cmp.b   D1,D0
    bne  _anon_z01_48
    even
_L_z01_SubQSpeedFromPositionFraction_SetCarry:
    move.b  (A5)+,D1  ; PLP: pop to CCR
    move.w  D1,CCR
    ori     #$11,CCR  ; SEC: set C+X
    move.w  SR,D1
    move.b  D1,-(A5)  ; PHP: push CCR
_anon_z01_48:
    move.b  (A5)+,D1  ; PLP: pop to CCR
    move.w  D1,CCR
    move.w  SR,D1
    move.b  D1,-(A5)  ; PHP: push CCR
    ; Subtract only carry from the grid offset.
    ; Carry represents whether the fractional position reached
    ; a whole pixel (C=0).
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    move.b  #$00,D1
    subx.b  D1,D0   ; SBC #$00
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  (A5)+,D1  ; PLP: pop to CCR
    move.w  D1,CCR
    rts

    even
OppositeDirs:
    dc.b    $04, $08, $01, $02

; Params:
; A: direction
;
; Returns:
; A: opposite direction
; Y: a reverse direction index
;
; The reverse direction index returned has this mapping:
; In Dir: 1 2 4 8
;         -------
; Index:  3 2 1 0
;
    even
GetOppositeDir:
    moveq   #3,D3
    even
_L_z01_GetOppositeDir_Loop:
    lsr.b  #1,D0   ; LSR A
    bcs  _anon_z01_49
    subq.b  #1,D3
    bpl  _L_z01_GetOppositeDir_Loop
_anon_z01_49:
    lea     (OppositeDirs).l,A0
    move.b  (A0,D3.W),D0
    rts

; Params:
; A: value
;
; Returns:
; A: absolute value
;
    even
Abs:
    bpl  _anon_z01_50
; Params:
; A: value
;
; Returns:
; A: result
;
    even
Negate:
    eori.b #$FF,D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$01,D1
    addx.b  D1,D0   ; ADC #$01 (X flag = 6502 C)
_anon_z01_50:
    rts

; Params:
; A: direction
; X: object index
; [0E]: 0 to change grid offset, else leave it as is
;
; Returns:
; [0E]: $80 if blocked
; [0F]: moving direction, or 0 if boundary was crossed
;
;
; If a boundary was crossed, go set [0E] to $80 instead of moving.
;
    even
MoveShot:
    jsr     BoundByRoomWithA
    beq  _L_z01_MoveShot_ReturnBlocked
    ; Move the object as if grid offset were 0.
    ;
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     MoveObject
    move.b  (A5)+,D0  ; PLA
    ; If [0E] is set, keep the original value in grid offset,
    ; or else add the new amount to it.
    ;
    moveq   #0,D3
    move.b  ($000E,A4),D3
    bne  _anon_z01_51
    andi    #$EE,CCR  ; CLC: clear C+X
    lea     ($0394,A4),A0
    move.b  (A0,D2.W),D1
    addx.b  D1,D0   ; ADC ObjGridOffset,X
_anon_z01_51:
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    rts

    even
_L_z01_MoveShot_ReturnBlocked:
    move.b  #$80,D0
    move.b  D0,($000E,A4)
    rts

; Params:
; A: object index of target
; X: object index of origin
; [00]: 0
;
; Returns:
; [00]: the number of axes where the distance <= 8
; [03]: distance X
; [04]: distance Y
; [0A]: vertical direction from origin to target
; [0B]: horizontal direction from origin to target
;
;
; Handle the horizontal.
;
    even
GetDirectionsAndDistancesToTarget:
    move.b  D0,-(A5)  ; PHA
    moveq   #0,D3
    move.b  D0,D3
    moveq   #2,D0
    move.b  D0,($000A,A4)
    move.b  ($70,A4,D3.W),D0
    moveq   #0,D3
    move.b  ($70,A4,D2.W),D3
    jsr     GetOneDirectionAndDistanceToTarget
    move.b  D0,($0003,A4)
    move.b  ($000A,A4),D0
    move.b  D0,($000B,A4)
    ; Handle the vertical.
    ;
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D3
    move.b  D0,D3
    moveq   #8,D0
    move.b  D0,($000A,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D3.W),D0
    moveq   #0,D3
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D3
    jsr     GetOneDirectionAndDistanceToTarget
    move.b  D0,($0004,A4)
    rts

; Params:
; Y: middle speed index (4)
; [03]: horizontal distance
; [04]: vertical distance
; [0A]: vertical direction
; [0B]: horizontal direction
;
; Returns:
; Y: speed index (0 to 8) for the angle
;
;
; TODO: call it speed index or angle?
; Store the middle speed index in [00]. It will be changed to the
; right speed index to use incrementally.
; Lower speed indexes yield faster X speeds and lower Y speeds.
; Higher speed indexes yield faster Y speeds and lower X speeds.
;
    even
_CalcDiagonalSpeedIndex:
    move.b  D3,($0000,A4)
    ; Assuming horizontal distance >= vertical distance, the
    ; index offset in [01] is negative (-1) to go towards the X axis.
    ;
    move.b  #$FF,D0
    move.b  D0,($0001,A4)
    ; TODO:
    ; If horizontal distance [03] < vertical distance [04], swap [03] and [04],
    ; and store positive speed index 1 in [01] to go towards the Y axis.
    ;
    ; The point is to put the greater value in [03] and the lesser one in [04],
    ; and use a speed index offset (1 or -1) that will point us in the direction
    ; of the farther distance faster.
    ;
    move.b  ($0003,A4),D0
    move.b  ($0004,A4),D1
    cmp.b   D1,D0
    bcc  _L_z01__CalcDiagonalSpeedIndex_Swap
    move.b  D0,-(A5)  ; PHA
    move.b  ($0004,A4),D0
    move.b  D0,($0003,A4)
    move.b  (A5)+,D0  ; PLA
    move.b  D0,($0004,A4)
    moveq   #1,D0
    move.b  D0,($0001,A4)
    even
_L_z01__CalcDiagonalSpeedIndex_Swap:
    ; TODO: call it speed index or angle?
    ; If the difference in distances is within 8 pixels,
    ; return the speed index (angle) we have.
    ;
    move.b  ($0003,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0004,A4),D1
    subx.b  D1,D0   ; SBC $04
    cmpi.b  #$08,D0
    bcs  _L_z01__CalcDiagonalSpeedIndex_Return
    even
_L_z01__CalcDiagonalSpeedIndex_Turn:
    ; TODO: call it speed index or angle?
    ; Otherwise, go to the next speed index (angle).
    ;
    move.b  ($0000,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0001,A4),D1
    addx.b  D1,D0   ; ADC $01
    move.b  D0,($0000,A4)
    ; TODO: call it speed index or angle?
    ; If a speed index (angle) limit (0 or 8), we've gone all the way to an axis
    ; (0, 90, 180, 270 degrees). So return this speed index (angle).
    ;
    beq  _L_z01__CalcDiagonalSpeedIndex_Return
    cmpi.b  #$08,D0
    beq  _L_z01__CalcDiagonalSpeedIndex_Return
    ; Subtract the lesser distance from the greater distance.
    ; If they still haven't crossed, then we can turn more.
    ;
    move.b  ($0003,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0004,A4),D1
    subx.b  D1,D0   ; SBC $04
    move.b  D0,($0003,A4)
    move.b  ($0004,A4),D1
    cmp.b   D1,D0
    bcc  _L_z01__CalcDiagonalSpeedIndex_Turn
    even
_L_z01__CalcDiagonalSpeedIndex_Return:
    ; TODO: call it speed index or angle?
    ; Return the speed index (angle) we found.
    ;
    moveq   #0,D3
    move.b  ($0000,A4),D3
    rts

; Params:
; A: q-speed fraction
;
    even
SetBoomerangSpeed:
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    ; If in major state $50, use this speed as is.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$F0,D0
    cmpi.b  #$40,D0
    bne  _L_z01_SetBoomerangSpeed_Exit
    ; Else, in major state $40, go at half the speed.
    ;
    lea     ($03BC,A4),A0
    move.b  (A0,D2.W),D1
    lsr.b  #1,D1   ; LSR ObjQSpeedFrac,X
    move.b  D1,(A0,D2.W)
    ; Once we've traveled the target amount of time, set state $50 to go faster.
    ; In major state $40, ObjMovingLimit is a timer to change the state to $50.
    ;
    lea     ($0380,A4),A0
    subq.b  #1,(A0,D2.W)
    bne  _L_z01_SetBoomerangSpeed_Exit
    moveq   #80,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z01_SetBoomerangSpeed_Exit:
    rts

; Params:
; A: target coordinate
; Y: origin coordinate
; [00]: a value
; [0A]: the decreasing direction on the coordinates' axis (2 or 8)
;
; Returns:
; A: the distance from origin to target
; [00]: the original value + 1, if < 8 pixels between origin and target
; [0A]: the direction from origin to target
;
;
; If the origin coordinate already >= target coordinate, then
; the direction in [0A] is already correct. Otherwise, shift it right
; to flip it.
;
; After this, [02] will >= [01].
;
    even
GetOneDirectionAndDistanceToTarget:
    move.b  D0,($0001,A4)
    move.b  D3,($0002,A4)
    move.b  ($0001,A4),D1
    cmp.b   D1,D3
    bcc  _L_z01_GetOneDirectionAndDistanceToTarget_Subtract
    move.b  D0,($0002,A4)
    move.b  D3,($0001,A4)
    move.b  ($000A,A4),D1
    lsr.b  #1,D1   ; LSR $0A
    move.b  D1,($000A,A4)
    even
_L_z01_GetOneDirectionAndDistanceToTarget_Subtract:
    ; If the difference between the coordinates < 9, increment [00].
    ;
    move.b  ($0002,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0001,A4),D1
    subx.b  D1,D0   ; SBC $01
    cmpi.b  #$09,D0
    bcc  _anon_z01_52
    addq.b  #1,($0000,A4)
_anon_z01_52:
    rts

    even
WieldBomb:
    ; If there are no bombs in inventory, return.
    ;
    move.b  ($0658,A4),D0
    beq  _anon_z01_52
    ; Look in slot $10. If it's empty or there's a fire
    ; (state = 0, or major state <> $10), then
    ; go activate a bomb.
    ;
    moveq   #16,D2
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z01_WieldBomb_FoundSlot
    andi.b #$F0,D0
    cmpi.b  #$10,D0
    bne  _L_z01_WieldBomb_FoundSlot
    ; Else look at slot $11.
    ; If there's a bomb there (major state = $10), then return.
    ;
    addq.b  #1,D2
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z01_WieldBomb_FoundSlot
    andi.b #$F0,D0
    cmpi.b  #$10,D0
    bne.s  __far_z_01_0031
    jmp  L69AB_Exit
__far_z_01_0031:
    even
_L_z01_WieldBomb_FoundSlot:
    ; We found a slot that's empty or has a fire. It could be $10 or $11.
    ; If the other slot has a bomb that's not yet detonating (state < $13),
    ; then return.
    ;
    move.b  D2,D0
    eori.b #$01,D0
    moveq   #0,D3
    move.b  D0,D3
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    beq  _L_z01_WieldBomb_Activate
    cmpi.b  #$13,D0
    bcc.s  __far_z_01_0032
    jmp  L69AB_Exit
__far_z_01_0032:
    even
_L_z01_WieldBomb_Activate:
    ; We're using a bomb. Decrement the count.
    ;
    subq.b  #1,($0658,A4)
    ; Play the "set a bomb" tune.
    ;
    moveq   #32,D0
    move.b  D0,($0604,A4)
    ; Reset the object timer.
    ;
    moveq   #0,D0
    move.b  D0,($28,A4,D2.W)
    ; Start in state $11.
    ;
    moveq   #17,D0
; Params:
; A: initial state
; X: object index
;
    even
PlaceWeaponForPlayerStateAndAnimAndWeaponState:
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    even
PlaceWeaponForPlayerStateAndAnim:
    ; Set player's animation counter to 1, so that it will roll over
    ; as soon as possible, causing movement frame to become 0 (legs apart),
    ; which is how we want to end item-use animations.
    ;
    ; Set player's state to $10 (wielding sword/item).
    ;
    moveq   #1,D0
    move.b  D0,($03D0,A4)
    even
PlaceWeaponForPlayerState:
    moveq   #16,D0
    move.b  D0,($00AC,A4)
; Places the weapon $10 pixels away from the player in the
; player's direction.
;
; Params:
; A: $10 for right and down
; X: object index
;
;
; Set the offset choices to:
;  $10 for right and down in [01]
; -$10 for left and up in [02]
;
    even
PlaceWeapon:
    move.b  #$F0,D3
    move.b  D0,($0001,A4)
    move.b  D3,($0002,A4)
    ; Set object's direction to the player's.
    ;
    move.b  ($0098,A4),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    ; Set object's X to player's X + offset for direction.
    ;
    jsr     ChooseOffsetForDirectionH
    move.b  ($0070,A4),D1
    addx.b  D1,D0   ; ADC ObjX
    move.b  D0,($70,A4,D2.W)
    ; Set object's Y to player's Y + offset for direction.
    ;
    move.b  ($0098,A4),D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    jsr     ChooseOffsetForDirectionH
    move.b  ($0084,A4),D1
    addx.b  D1,D0   ; ADC ObjY
    lea     ($0084,A4),A0
    move.b  D0,(A0,D2.W)
    even
L69AB_Exit:
    rts

; Params:
; A: direction
; [01]: value for right
; [02]: value for left
;
; Returns:
; A: chosen value, or 0 if not horizontal
; C: 0
;
;
; Set default value 0 in default address 0.
;
    even
ChooseOffsetForDirectionH:
    moveq   #0,D3
    move.b  D3,($0000,A4)
    andi.b #$03,D0
    beq  _L_z01_ChooseOffsetForDirectionH_GetValue
    addq.b  #1,D3
    andi.b #$01,D0
    bne  _L_z01_ChooseOffsetForDirectionH_GetValue
    addq.b  #1,D3
    even
_L_z01_ChooseOffsetForDirectionH_GetValue:
    move.b  ($00,A4,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    even
L69BE_Exit:
    rts

; Returns:
; X: last object slot tested, regardless of whether it's empty
;
; Fails if no empty slot was found, or the blue candle was already used.
;
;
; Look in slots $10 and $11. If none are empty, return.
; Otherwise, X will have the empty slot found.
;
; Note that it's possible that we fail to find an empty slot,
; but the caller might find slot X occupied by a fire made earlier.
;
    even
WieldCandle:
    moveq   #16,D2
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq  _L_z01_WieldCandle_NotInUse
    addq.b  #1,D2
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    beq.s  __far_z_01_0033
    jmp  L69BE_Exit
__far_z_01_0033:
    even
_L_z01_WieldCandle_NotInUse:
    ; If we have the blue candle and it was used, then return.
    ;
    move.b  ($065B,A4),D0
    cmpi.b  #$01,D0
    bne  _anon_z01_53
    move.b  ($0513,A4),D0
    beq.s  __far_z_01_0034
    jmp  L69BE_Exit
__far_z_01_0034:
_anon_z01_53:
    ; Set the candle used.
    ;
    moveq   #1,D0
    move.b  D0,($0513,A4)
    ; Reset the new fire object's movement info.
    ; Set quarter speed (q-speed) to $20 (half a pixel a frame).
    ;
    moveq   #0,D0
    lea     ($0394,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($03A8,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #32,D0
    lea     ($03BC,A4),A0
    move.b  D0,(A0,D2.W)
    ; Activate the fire object. Initial state = $21 (moving fire).
    ;
    moveq   #33,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #4,D0
    jsr     PlayEffect
    ; Each animation frame lasts 4 frames.
    ;
    moveq   #4,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D2.W)
    jsr     PlaceWeaponForPlayerState
    rts

; Returns:
; A: X coordinate of shortcut (OW) or item (UW)
; Y: Y coordinate of shortcut (OW) or item (UW)
;
    even
GetShortcutOrItemXY:
    moveq   #0,D3
    move.b  ($00EB,A4),D3
; Params:
; Y: room ID
;
; Returns:
; A: X coordinate of shortcut (OW) or item (UW)
; Y: Y coordinate of shortcut (OW) or item (UW)
;
    even
GetShortcutOrItemXYForRoom:
    lea     (NES_SRAM+$0AFE).l,A0
    move.b  (A0,D3.W),D0
    andi.b #$30,D0
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    lsr.b  #1,D0   ; LSR A
    moveq   #0,D3
    move.b  D0,D3
    lea     (NES_SRAM+$0BA7).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$0F,D0
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    moveq   #0,D3
    move.b  D0,D3
    move.b  (A5)+,D0  ; PLA
    andi.b #$F0,D0
    rts

; Params:
; A: 0
; X: object index
;
    even
DestroyObject_WRAM:
    lea     ($00C0,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($00D3,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D0,($28,A4,D2.W)
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D2.W)
    lea     ($04F0,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  #$FF,D0
    lea     ($0492,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #1,D0
    lea     ($0405,A4),A0
    move.b  D0,(A0,D2.W)
