GetRoomFlagUWItemState:
    move.b  (NES_SRAM+$0BAF).l,D0
    move.b  D0,($0008,A4)
    move.b  (NES_SRAM+$0BB0).l,D0
    move.b  D0,($0009,A4)
    moveq   #0,D3
    move.b  ($00EB,A4),D3
    move.b  ($08,A4),D1   ; ptr lo
    move.b  ($09,A4),D4  ; ptr hi
    andi.w  #$00FF,D1         ; zero-extend lo byte
    lsl.w   #8,D4
    or.w    D1,D4             ; D4 = NES ptr addr
    ext.l   D4
    add.l   #NES_RAM,D4       ; → Genesis addr
