; ObjTimer[12] is the world fade timer. Every 10 frames,
; we step to the next half palette. There are 4 steps to fading.
;
    even
AnimateWorldFading:
    move.b  ($0034,A4),D0
    bne  _L_z01_AnimateWorldFading_Exit
    move.b  ($051C,A4),D0
    bpl  _anon_z01_73
    eori.b #$83,D0
_anon_z01_73:
    move.b  D0,($0000,A4)
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    lsl.b  #1,D0   ; ASL A
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($0000,A4),D1
    addx.b  D1,D0   ; ADC $00
    andi.b #$FC,D0
    moveq   #0,D3
    move.b  D0,D3
    ; Start writing in dynamic transfer buf from the next position
    ; available. X holds this offset.
    moveq   #0,D2
    move.b  ($0301,A4),D2
    moveq   #63,D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D2
    moveq   #8,D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D2
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
