    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    addq.b  #1,D3
    addq.b  #1,D2
    subq.b  #1,($0000,A4)
    bne  _L_z01_AnimateWorldFading_CopyPalette
    move.b  #$FF,D0
    lea     ($0302,A4),A0
    move.b  D0,(A0,D2.W)
    move.b  D2,($0301,A4)
    addq.b  #1,($051C,A4)
    move.b  ($051C,A4),D0
    andi.b #$0F,D0
    cmpi.b  #$04,D0
    beq  _L_z01_AnimateWorldFading_ReturnDone
    moveq   #10,D0
    move.b  D0,($0034,A4)
