    move.b  D0,($0344,A4)
    moveq   #0,D3
    move.b  ($000E,A4),D3
    moveq   #1,D0
    move.b  D0,($0007,A4)
    moveq   #8,D0
    move.b  D0,($000A,A4)
    lea     (ObjAnimations).l,A0
    move.b  (A0,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  ($000D,A4),D1
    addx.b  D1,D0   ; ADC $0D
