    ; that capture Link.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    moveq   #0,D3
    lea     ($0405,A4),A0
    move.b  (A0,D2.W),D3
    beq  _L_z01_CheckMonsterCollisions_CheckCaptors
