    ;
    ; If it's a goriya that threw a boomerang, then destroy the boomerang.
    ;
    cmpi.b  #$05,D0
    beq  _anon_z01_81
    cmpi.b  #$06,D0
    bne  _L_z01_CheckMonsterCollisions_Exit
