    bpl  _L_z01_CheckMonsterCollisions_Exit
    moveq   #0,D3
    lea     ($042C,A4),A0
    move.b  (A0,D2.W),D3
    moveq   #0,D0
    lea     ($034F,A4),A0
    move.b  D0,(A0,D3.W)
    even
_L_z01_CheckMonsterCollisions_Exit:
