; Params:
; X: monster object index
;
; Returns:
; [00]: 0 for Link slot
; [06]: 1 if objects collide
; [09]: 0 for Link damage type (none)
; [0C]: 1 if objects collide
; [034B]: ShotCollidesWithLink
;
    even
CheckLinkCollision:
    jsr     GetObjectMiddle
    ; Reset variables to return.
    ;
    moveq   #0,D0
    move.b  D0,($034B,A4)
    move.b  D0,($0006,A4)
    move.b  D0,($0009,A4)
    move.b  D0,($000C,A4)
    moveq   #0,D3
    move.b  D3,($0000,A4)
    ; If Link is invincible, or we have the magic clock,
    ; or Link is stunned, or the monster is stunned;
    ; then return no collision.
    ;
    move.b  ($04F0,A4),D0
    move.b  ($066C,A4),D1
    or.b  D1,D0
    move.b  ($003D,A4),D1
    or.b  D1,D0
    move.b  ($3D,A4,D2.W),D1
    or.b  D1,D0
    beq.s  __far_z_01_0060
    jmp  L73A9_Exit
__far_z_01_0060:
    even
CheckLinkCollisionPreinit:
    ; If Link is halted or paralyzed, then return no collision.
    ;
    move.b  ($00AC,A4),D0
    cmpi.b  #$40,D0
    bne.s  __far_z_01_0061
    jmp  L73A9_Exit
__far_z_01_0061:
    move.b  ($0512,A4),D0
    beq.s  __far_z_01_0062
    jmp  L73A9_Exit
__far_z_01_0062:
    ; If the object is a monster's shot/projectile, and it's not in a
    ; state that it can do damage; then return no collision.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$53,D0
    bcs  _anon_z01_84
    lea     ($00AC,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$F0,D0
    cmpi.b  #$10,D0
    beq.s  __far_z_01_0063
    jmp  L73A9_Exit
__far_z_01_0063:
_anon_z01_84:
    ; Store Link's midpoint coordinates in [04] and [05].
    ;
    move.b  ($0070,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0004,A4)
    move.b  ($0084,A4),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0005,A4)
    ; If both objects are 9 pixels apart or more, then return no collision.
    ;
    moveq   #9,D0
    jsr     DoObjectsCollide
    bne.s  __far_z_01_0064
    jmp  L73A9_Exit
__far_z_01_0064:
    ; They collide. Now find out how they collide.
    ;
    ; If it's a regular monster, go harm Link.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$53,D0
    bcc.s  __far_z_01_0065
    jmp  HarmLink
__far_z_01_0065:
    ; Here, the attacker is a monster's shot/projectile.
    ; Flag this kind of collision.
    ;
    addq.b  #1,($034B,A4)
    ; If object type = Fireball2 ($56) or $5A, or Link is not idle;
    ; then go harm Link.
    ;
    cmpi.b  #$56,D0
    bne.s  __far_z_01_0066
    jmp  HarmLink
__far_z_01_0066:
    cmpi.b  #$5A,D0
    bne.s  __far_z_01_0067
    jmp  HarmLink
__far_z_01_0067:
    move.b  ($00AC,A4),D0
    andi.b #$F0,D0
    beq.s  __far_z_01_0068
    jmp  HarmLink
__far_z_01_0068:
    ; If Link and the shot are not facing opposite directions,
    ; then go harm Link.
    ;
    ; Note the bitwise AND in the test. It picks out one direction
    ; component of a monster that can move diagonally.
    ;
    move.b  ($0098,A4),D0
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    or.b  D1,D0
    andi.b #$0C,D0
    cmpi.b  #$0C,D0
    beq  _L_z01_CheckLinkCollisionPreinit_FacingOpposite
    move.b  ($0098,A4),D0
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    or.b  D1,D0
    andi.b #$03,D0
    cmpi.b  #$03,D0
    beq.s  __far_z_01_0069
    jmp  HarmLink
__far_z_01_0069:
    even
_L_z01_CheckLinkCollisionPreinit_FacingOpposite:
    ; Link and the shot are facing opposite directions.
    ; Link can parry certain weapons/shots.
    ;
    ; For flying rock, $54, arrow, and boomerang, this means
    ; no harmful collision; but it still counts as a shot collision.
    ; So, go treat this as a parry.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$55,D0
    bcs  _L_z01_CheckLinkCollisionPreinit_Parry
    cmpi.b  #$5B,D0
    bcc  _L_z01_CheckLinkCollisionPreinit_Parry
    ; If the magic shield is missing, then the rest of the shots do damage.
    ; So, go harm Link.
    ;
    move.b  ($0676,A4),D0
    bne.s  __far_z_01_0070
    jmp  HarmLink
__far_z_01_0070:
    even
_L_z01_CheckLinkCollisionPreinit_Parry:
    ; Else Link parries.
    ;
    ; Play the "parry" tune, and cancel the collision (reset [06]).
    ;
    moveq   #1,D0
    move.b  D0,($0604,A4)
    moveq   #0,D0
    move.b  D0,($0006,A4)
    even
L73A9_Exit:
    rts

    even
HarmLink:
    jsr     BeginShove
    ; Flag collision with [0C], even though [06] was already set.
    ;
    addq.b  #1,($000C,A4)
    ; Unpack the damage points for the monster's type.
    ; The low nibble is the high byte.
    ; (Damage points byte AND $F0) is the low byte.
    ;
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    lea     (ObjTypeToDamagePoints).l,A0
    move.b  (A0,D3.W),D0
    move.b  D0,-(A5)  ; PHA
    andi.b #$0F,D0
    move.b  D0,($000D,A4)
    move.b  (A5)+,D0  ; PLA
    andi.b #$F0,D0
    move.b  D0,($000E,A4)
; Params:
; X: object index of the attacker
; [0D]: damage points high byte
; [0E]: damage points low byte
;
;
; If object type is not whirlwind, then make the "hurt" sound effect.
;
    even
Link_BeHarmed:
    moveq   #0,D3
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D3
    cmpi.b  #$2E,D3
    beq  _anon_z01_85
    moveq   #8,D0
    jsr     PlaySample
_anon_z01_85:
    ; For every level of ring (1 or 2), divide the 16-bit damage amount in [0E:0D] by 2.
    ;
    moveq   #0,D3
    move.b  ($0662,A4),D3
    beq  _L_z01_Link_BeHarmed_ResetHelp
_anon_z01_86:
    move.b  ($000D,A4),D1
    lsr.b  #1,D1   ; LSR $0D
    move.b  D1,($000D,A4)
    move.b  ($000E,A4),D1
    roxr.b  #1,D1   ; ROR $0E
    move.b  D1,($000E,A4)
    subq.b  #1,D3
    bne  _anon_z01_86
    even
_L_z01_Link_BeHarmed_ResetHelp:
    ; Reset values used in special item drops.
    ;
    moveq   #0,D0
    move.b  D0,($0627,A4)
    move.b  D0,($0050,A4)
    move.b  D0,($0051,A4)
    ; If heart partial >= low damage points byte, then simply
    ; subtract the damage byte from heart partial.
    ; Else go borrow from full hearts.
    ;
    move.b  ($0670,A4),D0
    move.b  ($000E,A4),D1
    cmp.b   D1,D0
    bcs  _L_z01_Link_BeHarmed_BorrowHeart
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($000E,A4),D1
    subx.b  D1,D0   ; SBC $0E
    move.b  D0,($0670,A4)
    ; If full hearts >= high damage points byte, then simply
    ; subtract the damage byte from full hearts.
    ; Else go handle Link dying.
    ;
    move.b  ($066F,A4),D0
    andi.b #$0F,D0
    move.b  ($000D,A4),D1
    cmp.b   D1,D0
    bcs  _L_z01_Link_BeHarmed_HandleDied
    move.b  ($066F,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($000D,A4),D1
    subx.b  D1,D0   ; SBC $0D
    move.b  D0,($066F,A4)
    rts

    even
_L_z01_Link_BeHarmed_BorrowHeart:
    ; This isn't a simple case of borrowing. For example, supposing:
    ;   full heart=4 partial heart=$70
    ; The straightforward way to subtract $80 would yield $3F0.
    ; But the method here yields $3EF, because partial heart is
    ; considered full when = $FF instead of $100.
    ;
    move.b  ($000E,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0670,A4),D1
    subx.b  D1,D0   ; SBC HeartPartial
    move.b  D0,($000E,A4)
    move.b  ($066F,A4),D0
    andi.b #$0F,D0
    beq  _L_z01_Link_BeHarmed_HandleDied
    subq.b  #1,($066F,A4)
    move.b  #$FF,D0
    move.b  D0,($0670,A4)
    bne  _L_z01_Link_BeHarmed_ResetHelp
    even
_L_z01_Link_BeHarmed_HandleDied:
    ; Link died.
    ;
    ; Set full hearts, partial heart, and Link's object state to 0.
    ; Make Link face down.
    ; Go to mode $11.
    ;
    move.b  ($066F,A4),D0
    andi.b #$F0,D0
    move.b  D0,($066F,A4)
    jsr     EndGameMode
    move.b  D0,($0670,A4)
    move.b  D0,($00AC,A4)
    moveq   #17,D0
    move.b  D0,($0012,A4)
    moveq   #4,D0
    move.b  D0,($0098,A4)
_anon_z01_87:
    rts

; Params:
; X: monster slot
; Y: weapon slot
; [02]: monster mid X
; [03]: monster mid Y
;
; Returns:
; [00]: weapon slot
;
; If the weapon slot holds food (high bit of state is set), then return.
;
    even
CheckMonsterBoomerangOrFoodCollision:
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    lsl.b  #1,D0   ; ASL A
    bcs  _anon_z01_87
    move.b  D3,($0000,A4)
    ; Set boomerang damage type (2) in [09].
    ;
    moveq   #2,D0
    move.b  D0,($0009,A4)
    ; Set collision threshold $A in both axes.
    ;
    moveq   #10,D0
    move.b  D0,($000D,A4)
    move.b  D0,($000E,A4)
    ; The boomerang's middle X is 4 pixels to the right. Store in [04].
    ;
    move.b  ($70,A4,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$04,D1
    addx.b  D1,D0   ; ADC #$04 (X flag = 6502 C)
    move.b  D0,($0004,A4)
    ; The boomerang's middle Y is 8 pixels down. Store in [05].
    ;
    lea     ($0084,A4),A0
    move.b  (A0,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
; Params:
; A: weapon object mid Y
; X: monster object slot
; Y: weapon object slot
; [00]: weapon object slot
; [02]: monster object mid X
; [03]: monster object mid Y
; [04]: weapon object mid X
; [07]: damage points
; [09]: damage type
; [0D]: horizontal threshold
; [0E]: vertical threshold
;
; Returns:
; [06]: 1 if objects collide
;
    even
CheckMonsterWeaponCollision:
    move.b  D0,($0005,A4)
    ; Reset [06] for no collision.
    ;
    moveq   #0,D0
    move.b  D0,($0006,A4)
    ; If the weapon's not active (state = 0), then return.
    ;
    moveq   #0,D3
    move.b  ($0000,A4),D3
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    bne.s  __far_z_01_0071
    jmp  L74D8_Exit
__far_z_01_0071:
    ; If the objects do not collide, then return.
    ;
    jsr     DoObjectsCollideWithThresholds
    bne.s  __far_z_01_0072
    jmp  L74D8_Exit
__far_z_01_0072:
    ; If the weapon is a boomerang ...
    ;
    cmpi.b  #$0F,D3
    beq.s  __far_z_01_0073
    jmp  HandleMonsterWeaponCollision
__far_z_01_0073:
    ; ... and the monster is invincible to it,
    ; then play the parry sound.
    ;
    lea     ($04B2,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0009,A4),D1
    and.b  D1,D0
    beq  _anon_z01_88
    jsr     PlayParryTune
_anon_z01_88:
    ; Set the boomerang state to return fast to the thrower.
    ;
    moveq   #80,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D3.W)
    ; If the monster is invincible to the boomerang, then return.
    ;
    lea     ($04B2,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0009,A4),D1
    and.b  D1,D0
    beq.s  __far_z_01_0074
    jmp  L74D8_Exit
__far_z_01_0074:
    ; Still the boomerang.
    ; Reset [07] damage points, and set the monster's stun timer to $10 ($A0 frames).
    ;
    moveq   #0,D0
    move.b  D0,($0007,A4)
    moveq   #16,D0
    move.b  D0,($3D,A4,D2.W)
    even
HandleMonsterWeaponCollision:
    ; If the monster is invincible to this damage type, then
    ; go play parry sound if needed, and return.
    ;
    lea     ($04B2,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0009,A4),D1
    and.b  D1,D0
    beq.s  __far_z_01_0075
    jmp  L_PlayParrySoundForDamageType
__far_z_01_0075:
    ; If the monster is Blue Gohma or Red Gohma, then
    ; let it handle the collision.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$33,D0
    beq  _anon_z01_89
    cmpi.b  #$34,D0
    bne  _L_z01_HandleMonsterWeaponCollision_CheckZolVire
_anon_z01_89:
    jmp     Gohma_HandleWeaponCollision

    even
_L_z01_HandleMonsterWeaponCollision_CheckZolVire:
    ; If the monster is Zol or Vire, then
    ;   If not hit by the boomerang, then
    ;     Set monster's direction to the weapon's
    ;   Go deal damage
    ;
    cmpi.b  #$13,D0
    beq  _anon_z01_90
    cmpi.b  #$12,D0
    bne  _L_z01_HandleMonsterWeaponCollision_CheckDarknut
_anon_z01_90:
    cmpi.b  #$0F,D3
    bne.s  __far_z_01_0076
    jmp  DealDamage
__far_z_01_0076:
    lea     ($0098,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     DealDamage

    even
_L_z01_HandleMonsterWeaponCollision_CheckDarknut:
    ; If the monster is a red or blue darknut, and it and the weapon
    ; are facing opposite directions, then only play the parry sound.
    ;
    cmpi.b  #$0B,D0
    beq  _anon_z01_91
    cmpi.b  #$0C,D0
    beq.s  __far_z_01_0077
    jmp  DealDamage
__far_z_01_0077:
_anon_z01_91:
    lea     ($0098,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    or.b  D1,D0
    cmpi.b  #$0C,D0
    bne.s  __far_z_01_0078
    jmp  L_PlayParrySoundForDamageType
__far_z_01_0078:
    cmpi.b  #$03,D0
    bne.s  __far_z_01_0079
    jmp  L_PlayParrySoundForDamageType
__far_z_01_0079:
    even
DealDamage:
    ; Play the "harmed" sound.
    ;
    moveq   #2,D0
    move.b  D0,($0604,A4)
    ; Subtract the damage points from HP; if damage points >= HP,
    ; then go handle the monster dying.
    ;
    lea     ($0485,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0007,A4),D1
    cmp.b   D1,D0
    bcc.s  __far_z_01_0080
    jmp  HandleMonsterDied
__far_z_01_0080:
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0007,A4),D1
    subx.b  D1,D0   ; SBC $07
    lea     ($0485,A4),A0
    move.b  D0,(A0,D2.W)
    bne.s  __far_z_01_0081
    jmp  HandleMonsterDied
__far_z_01_0081:
    even
L74D8_Exit:
    rts

    even
L_PlayParrySoundForDamageType:
    ; Play the parry sound for all but fire and bomb damage types.
    ;
    move.b  ($0009,A4),D0
    cmpi.b  #$20,D0
    bne.s  __far_z_01_0082
    jmp  L74D8_Exit
__far_z_01_0082:
    cmpi.b  #$08,D0
    bne.s  __far_z_01_0083
    jmp  L74D8_Exit
__far_z_01_0083:
    jmp     PlayParryTune

    even
HandleMonsterDied:
    ; Handle the monster dying.
    ;
    addq.b  #1,($0627,A4)
    ; Increase the help drop counter, if not at max ($A).
    ;
    move.b  ($0050,A4),D0
    cmpi.b  #$0A,D0
    bcc  _L_z01_HandleMonsterDied_SetDyingMetastate
    addq.b  #1,($0050,A4)
    ; If the help drop counter has reached the max, and damage type = bomb (8);
    ; then set [51] HelpDropValue in order to drop a bomb next time.
    ;
    move.b  ($0050,A4),D0
    cmpi.b  #$0A,D0
    bne  _L_z01_HandleMonsterDied_SetDyingMetastate
    move.b  ($0009,A4),D0
    cmpi.b  #$08,D0
    bne  _L_z01_HandleMonsterDied_SetDyingMetastate
    addq.b  #1,($0051,A4)
    even
_L_z01_HandleMonsterDied_SetDyingMetastate:
    ; Set the dying metastate, and reset some object info.
    ;
    jsr     UpdateDeadDummy
    moveq   #0,D0
    move.b  D0,($3D,A4,D2.W)
; Params:
; A: 0
;
    even
ResetShoveInfoAndInvincibilityTimer:
    jsr     SetShoveInfoWith0
    lea     ($04F0,A4),A0
    move.b  D0,(A0,D2.W)
    rts

; Params:
; X: monster slot
; Y: weapon slot
; [02]: monster mid X
; [03]: monster mid Y
;
; Returns:
; [00]: weapon slot
;
; [00] holds the weapon slot
    even
CheckMonsterSwordShotOrMagicShotCollision:
    move.b  D3,($0000,A4)
    ; Set magic shot damage type ($10) in [09].
    ;
    moveq   #16,D0
    move.b  D0,($0009,A4)
    ; If the shot is a sword shot that's spreading out, then return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    lsr.b  #1,D0   ; LSR A
    bcs  _L_z01_CheckMonsterSwordShotOrMagicShotCollision_Exit
    ; Set horizontal collision threshold $C.
    ;
    moveq   #12,D0
    move.b  D0,($000D,A4)
    ; If the weapon is a magic shot, go use $20 damage points.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    moveq   #32,D3
    lsl.b  #1,D0   ; ASL A
    bcs  _L_z01_CheckMonsterSwordShotOrMagicShotCollision_CheckCollision
    ; The weapon is a sword shot.
    ;
    ; First, change the damage type to sword (1).
    ;
    moveq   #1,D0
    move.b  D0,($0009,A4)
    ; Determine the damage points for the kind of sword.
    ; - wood sword:   $10
    ; - white sword:  $20
    ; - master sword: $40
    ;
    moveq   #64,D3
    move.b  ($0657,A4),D0
    cmpi.b  #$03,D0
    beq  _L_z01_CheckMonsterSwordShotOrMagicShotCollision_CheckCollision
    moveq   #32,D3
    cmpi.b  #$02,D0
    beq  _L_z01_CheckMonsterSwordShotOrMagicShotCollision_CheckCollision
    moveq   #16,D3
    even
_L_z01_CheckMonsterSwordShotOrMagicShotCollision_CheckCollision:
    move.b  D3,D0
    jsr     CheckMonsterShotCollision
    ; If no collision, then return.
    ;
    move.b  ($0006,A4),D0
    beq  _L_z01_CheckMonsterSwordShotOrMagicShotCollision_Exit
    ; Else handle blocking the shot.
    ;
    move.b  D2,D0
    move.b  D0,-(A5)  ; PHA
    moveq   #14,D2
    jsr     HandleShotBlocked
    move.b  (A5)+,D0  ; PLA
    moveq   #0,D2
    move.b  D0,D2
    even
_L_z01_CheckMonsterSwordShotOrMagicShotCollision_Exit:
    rts

; Params:
; X: monster slot
; Y: weapon slot
; [02]: monster mid X
; [03]: monster mid Y
;
; Returns:
; [00]: weapon slot
;
; [00] holds the weapon slot
    even
CheckMonsterBombOrFireCollision:
    move.b  D3,($0000,A4)
    ; Set up parameters for a fire.
    ;
    moveq   #32,D0
    move.b  D0,($0009,A4)
    moveq   #16,D0
    move.b  D0,($0007,A4)
    moveq   #14,D0
    move.b  D0,($000D,A4)
    ; If the weapon is a fire, then go set the hotspot/midpoint.
    ; But if the bomb is not detonating, then return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$20,D0
    bcc  _L_z01_CheckMonsterBombOrFireCollision_SetHotspot
    cmpi.b  #$13,D0
    beq.s  __far_z_01_0084
    jmp  L7595_Exit
__far_z_01_0084:
    ; Else set up parameters for a bomb.
    ;
    moveq   #8,D0
    move.b  D0,($0009,A4)
    moveq   #64,D0
    move.b  D0,($0007,A4)
    moveq   #24,D0
    move.b  D0,($000D,A4)
    even
_L_z01_CheckMonsterBombOrFireCollision_SetHotspot:
    ; The weapon's midpoint/hotspot is at (X + 8, Y + 8).
    ; Pass it in [04] and [05].
    ;
    move.b  ($70,A4,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0004,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0005,A4)
    move.b  ($000D,A4),D0
    ; If the objects do not collide, then return.
    ;
    jsr     DoObjectsCollide
    bne.s  __far_z_01_0085
    jmp  L7595_Exit
__far_z_01_0085:
    jsr     HandleMonsterWeaponCollision
    ; If the monster is weak to the damage type, then shove it.
    ;
    lea     ($04B2,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0009,A4),D1
    and.b  D1,D0
    beq.s  __far_z_01_0086
    jmp  L7595_Exit
__far_z_01_0086:
    jsr     BeginShove
    even
L7595_Exit:
    rts

    even
SwordDamagePoints:
    dc.b    $10, $20, $40

; Params:
; X: monster slot
; Y: weapon slot
; [02]: monster mid X
; [03]: monster mid Y
;
; Returns:
; [00]: weapon slot
; [06]: 1 if objects collide
;
; [00] holds the weapon slot
    even
CheckMonsterSwordCollision:
    move.b  D3,($0000,A4)
    ;Set sword damage type (1) in [09].
    ;
    moveq   #1,D0
    move.b  D0,($0009,A4)
    ; If the sword is not fully extended, then return.
    ;
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    cmpi.b  #$02,D0
    beq.s  __far_z_01_0087
    jmp  L7595_Exit
__far_z_01_0087:
