    lea     (SwordDamagePoints-1).l,A0
    move.b  (A0,D3.W),D0
; Params:
; A: damage points
; X: monster slot
; Y: weapon slot
; [02]: monster mid X
; [03]: monster mid Y
; [09]: damage type
;
; Returns:
; [06]: 1 if objects collide
;
; [07] damage points
    even
CheckMonsterStabbingCollision:
    move.b  D0,($0007,A4)
    ; If Link's direction is vertical, then set collision thresholds accordingly:
    ; [0D] := $C
    ; [0E] := $10
    ;
    move.b  ($0098,A4),D0
    andi.b #$0C,D0
    beq  _L_z01_CheckMonsterStabbingCollision_Horizontal
    moveq   #12,D0
    move.b  D0,($000D,A4)
    moveq   #16,D0
    jmp     _anon_z01_92

    even
_L_z01_CheckMonsterStabbingCollision_Horizontal:
    ; Else switch it:
    ; [0D] := $10
    ; [0E] := $C
    ;
    moveq   #16,D0
    move.b  D0,($000D,A4)
    moveq   #12,D0
_anon_z01_92:
    move.b  D0,($000E,A4)
    jsr     CheckMonsterSlenderWeaponCollision2
    ; If no collision, then return.
    ;
    move.b  ($0006,A4),D0
    bne.s  __far_z_01_0088
    jmp  L7595_Exit
__far_z_01_0088:
    jmp     ParryOrShove

; Params:
; X: monster slot
; Y: weapon slot
; [02]: monster mid X
; [03]: monster mid Y
;
; Returns:
; [00]: weapon slot
; [06]: 1 if objects collide
;
; [00] holds the weapon slot
    even
CheckMonsterArrowOrRodCollision:
    move.b  D3,($0000,A4)
    lea     ($00AC,A4),A0
    move.b  (A0,D3.W),D0
    ; If the weapon is a rod, then
    ; go check a stabbing collision using rod parameters.
    ;
    cmpi.b  #$30,D0
    bcs  _anon_z01_93
    moveq   #1,D0
    move.b  D0,($0009,A4)
    moveq   #32,D0
    beq.s  __far_z_01_0089
    jmp  CheckMonsterStabbingCollision
__far_z_01_0089:
_anon_z01_93:
    ; We have an arrow. If it's no longer flying, then return.
    ;
    cmpi.b  #$20,D0
    bcs.s  __far_z_01_0090
    jmp  L763A_Exit
__far_z_01_0090:
    ; Set up arrow parameters.
    ;
    moveq   #4,D0
    move.b  D0,($0009,A4)
    ; Use $20 damage points for wooden arrows, and $40 for silver ones.
    ;
    moveq   #32,D0
    moveq   #0,D3
    move.b  ($0659,A4),D3
    cmpi.b  #$01,D3
    beq  _anon_z01_94
    lsl.b  #1,D0   ; ASL A
_anon_z01_94:
    moveq   #11,D3
    move.b  D3,($000D,A4)
; Params:
; A: damage points
; X: monster object slot
; [00]: weapon object slot
; [02]: monster object mid X
; [03]: monster object mid Y
; [09]: damage type
; [0D]: horizontal threshold
;
; Returns:
; [06]: 1 if objects collide
;
    even
CheckMonsterShotCollision:
    jsr     CheckMonsterSlenderWeaponCollision
    ; If no collision, return.
    ;
    move.b  ($0006,A4),D0
    bne.s  __far_z_01_0091
    jmp  L763A_Exit
__far_z_01_0091:
    ; $12 is the arrow and rod slot. But this routine will only
    ; be called if it's an arrow.
    ;
    ; If the weapon is an arrow and the monster is Pol's Voice;
    ; then set HP to 0, and deal damage, even if the collision
    ; checking routine above dealt some. This way it dies for sure.
    ;
    cmpi.b  #$12,D3
    beq.s  __far_z_01_0092
    jmp  ParryOrShove
__far_z_01_0092:
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$16,D0
    bne  _anon_z01_95
    moveq   #0,D0
    lea     ($0485,A4),A0
    move.b  D0,(A0,D2.W)
    jmp     DealDamage

_anon_z01_95:
    ; If the weapon is an arrow, set its state to spark ($20).
    ;
    moveq   #32,D0
    lea     ($00AC,A4),A0
    move.b  D0,(A0,D3.W)
    moveq   #3,D0
    lea     ($03D0,A4),A0
    move.b  D0,(A0,D3.W)
    even
ParryOrShove:
    ; For any weapon type:
    ;
    ; If the monster is a darknut and both are facing opposite directions,
    ; then go parry.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$0B,D0
    beq  _anon_z01_96
    cmpi.b  #$0C,D0
    bne  _anon_z01_97
_anon_z01_96:
    lea     ($0098,A4),A0
    move.b  (A0,D3.W),D0
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D1
    or.b  D1,D0
    cmpi.b  #$0C,D0
    bne.s  __far_z_01_0093
    jmp  PlayParryTune
__far_z_01_0093:
    cmpi.b  #$03,D0
    bne.s  __far_z_01_0094
    jmp  PlayParryTune
__far_z_01_0094:
_anon_z01_97:
    ; Else shove the monster.
    ;
    jmp     BeginShove

    even
PlayParryTune:
    moveq   #1,D0
    move.b  D0,($0604,A4)
    even
L763A_Exit:
    rts

; Params:
; A: damage points
; X: monster object slot
; [00]: weapon object slot
; [02]: monster object mid X
; [03]: monster object mid Y
; [09]: damage type
; [0D]: horizontal threshold
;
; Returns:
; [06]: 1 if objects collide
; [07]: damage points
; [0E]: vertical threshold
;
    even
CheckMonsterSlenderWeaponCollision:
    move.b  D0,($0007,A4)
    move.b  ($000D,A4),D0
    move.b  D0,($000E,A4)
; Params:
; X: monster object slot
; [00]: weapon object slot
; [02]: monster object mid X
; [03]: monster object mid Y
; [07]: damage points
; [09]: damage type
; [0D]: horizontal threshold
; [0E]: vertical threshold
;
; Returns:
; [06]: 1 if objects collide
;
    even
CheckMonsterSlenderWeaponCollision2:
    moveq   #0,D3
    move.b  ($0000,A4),D3
    ; If Link is facing vertically, then:
    ; [04] := (weapon X + 6)
    ; A    := (weapon Y + 8)
    ;
    ; Shouldn't it be based on the weapon's direction?
    ;
    move.b  ($0098,A4),D0
    andi.b #$0C,D0
    beq  _L_z01_CheckMonsterSlenderWeaponCollision2_CheckHorizontal
    move.b  ($70,A4,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$06,D1
    addx.b  D1,D0   ; ADC #$06 (X flag = 6502 C)
    move.b  D0,($0004,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    jmp     _anon_z01_98

    even
_L_z01_CheckMonsterSlenderWeaponCollision2_CheckHorizontal:
    ; Else Link is facing horizontally.
    ; [04] := (weapon X + 8)
    ; A    := (weapon Y + 6)
    ;
    ; Shouldn't it be based on the weapon's direction?
    ;
    move.b  ($70,A4,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$08,D1
    addx.b  D1,D0   ; ADC #$08 (X flag = 6502 C)
    move.b  D0,($0004,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D3.W),D0
    andi    #$EE,CCR  ; CLC: clear C+X
    move.b  #$06,D1
    addx.b  D1,D0   ; ADC #$06 (X flag = 6502 C)
_anon_z01_98:
    ; The A register will be copied to [05] and used here.
    ;
    jmp     CheckMonsterWeaponCollision

; Params:
; A: collision distance threshold (objects collide if nearer in X and Y)
; [00]: weapon object slot (unused)
; [02]: object 1 mid X
; [03]: object 1 mid Y
; [04]: object 2 mid X
; [05]: object 2 mid Y
;
; Returns:
; A: 1 if objects collide
; Y: weapon object slot
; Z: 0 if objects collide
; [06]: 1 if objects collide
; [0A]: horizontal distance
; [0B]: vertical distance
;
;
; Use the same threshold value horizontally and vertically.
; Copy it to [0D] for horizontal threshold, and [0E] for vertical one.
;
    even
DoObjectsCollide:
    move.b  D0,($000D,A4)
    move.b  D0,($000E,A4)
; Params:
; [00]: weapon or Link object slot (unused)
; [02]: object 1 mid X
; [03]: object 1 mid Y
; [04]: object 2 mid X
; [05]: object 2 mid Y
; [0D]: horizontal threshold
; [0E]: vertical threshold
;
; Returns:
; A: 1 if objects collide
; Y: weapon or Link object slot (copied from [00])
; Z: 0 if objects collide
; [06]: 1 if objects collide
; [0A]: horizontal distance
; [0B]: vertical distance
;
;
; Reset [06] to indicate no collision by default.
;
    even
DoObjectsCollideWithThresholds:
    moveq   #0,D0
    move.b  D0,($0006,A4)
    moveq   #0,D3
    move.b  ($0000,A4),D3
    ; Store in [0A] the horizontal distance between the two objects.
    ;
    move.b  ($0002,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0004,A4),D1
    subx.b  D1,D0   ; SBC $04
    jsr     Abs
    move.b  D0,($000A,A4)
    ; If distance >= horizontal threshold in [0D], return 0.
    ;
    move.b  ($000D,A4),D1
    cmp.b   D1,D0
    bcc  _L_z01_DoObjectsCollideWithThresholds_ReturnValue
    ; Store in [0B] the vertical distance between the two objects.
    ;
    move.b  ($0003,A4),D0
    ori     #$11,CCR  ; SEC: set C+X
    move.b  ($0005,A4),D1
    subx.b  D1,D0   ; SBC $05
    jsr     Abs
    move.b  D0,($000B,A4)
    ; If distance >= vertical threshold in [0E], return 0.
    ;
    move.b  ($000E,A4),D1
    cmp.b   D1,D0
    bcc  _L_z01_DoObjectsCollideWithThresholds_ReturnValue
    ; If we get here, then the objects are close enough in both axes.
    ; Return 1.
    ;
    addq.b  #1,($0006,A4)
    even
_L_z01_DoObjectsCollideWithThresholds_ReturnValue:
    move.b  ($0006,A4),D0
    rts

; Params:
; X: caller's object index, a monster
;    the attacker, if monster attacks Link
;    else defender, if weapon attacks monster
; [00]: 0 if monster attacks Link (defender),
;       else weapon slot (attacker)
; [09]: damage type,
;       only if a monster is defending
; TODO:
; [0B]: direction
;
; Only monsters (and fire) call this routine.
;
; When monsters attack Link, they set [00] to 0 for Link's slot.
;
; On the other hand, if a weapon attacks a monster,
; the monster sets [00] to the weapon's slot.
;
;
; If a weapon attacks a monster, and the weapon's damage
; type matches the monster's invincibility mask;
; then return without shoving.
;
; If a monster attacks Link, then damage type will be 0.
;
    even
BeginShove:
    moveq   #0,D3
    move.b  ($0000,A4),D3
    cmpi.b  #$0D,D2
    bcc  _anon_z01_99
    lea     ($04B2,A4),A0
    move.b  (A0,D2.W),D0
    move.b  ($0009,A4),D1
    and.b  D1,D0
    bne  _L_z01_BeginShove_Exit
_anon_z01_99:
    ; [08], [04], and [05] are used in determining the direction to push Link,
    ; if he is defending. The goal is to push Link away from the monster.
    ;
    ; If instead a monster is defending, then all this calculation
    ; won't matter, because the shove direction will be set to the
    ; weapon's direction.
    ;
    ; As such, calculate a direction from the monster to the defender,
    ; assuming it's Link.
    ;
    ; Start with an assumption that the direction is vertical:
    ; Store 8 (up) in [08], monster Y in [04], and other Y in [05].
    ;
    moveq   #8,D0
    move.b  D0,($0008,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D2.W),D0
    move.b  D0,($0004,A4)
    lea     ($0084,A4),A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0005,A4)
    ; If the defender is Link and his grid offset <> 0 then
    ; use his usual object direction variable to determine
    ; which axis to check.
    ;
    cmpi.b  #$00,D3
    bne  _anon_z01_100
    move.b  ($0394,A4),D0
    beq  _anon_z01_100
    move.b  ($0098,A4),D0
    andi.b #$03,D0
    bne  _L_z01_BeginShove_CheckHorizontal
    beq  _L_z01_BeginShove_CheckVertical
_anon_z01_100:
    ; For monsters defending, or Link with grid offset = 0,
    ; check direction in [0B].
    ;
    ; For monsters defending, this won't matter. For Link with grid
    ; offset = 0, I believe the result will be arbitrary.
    ;
    ; TODO:
    ; Is [0B] always set if Link's grid offset = 0?
    ; It doesn't seem to be if candle fire attacks him.
    ;
    move.b  ($000B,A4),D0
    cmpi.b  #$04,D0
    bcc  _L_z01_BeginShove_CheckVertical
    even
_L_z01_BeginShove_CheckHorizontal:
    ; If the direction checked is left or right,
    ; set [08] to 2 (left), monster X in [04] and other X in [05].
    ;
    moveq   #2,D0
    move.b  D0,($0008,A4)
    move.b  ($70,A4,D2.W),D0
    move.b  D0,($0004,A4)
    move.b  ($70,A4,D3.W),D0
    move.b  D0,($0005,A4)
    even
_L_z01_BeginShove_CheckVertical:
    ; If the monster is down or right of the other object,
    ; then use the opposite direction already in [08].
    ; Else shift [08] right to turn it into the opposite
    ; direction up or down.
    ;
    ; Again assuming Link is the defender; after this, [08] points
    ; Link away from the monster.
    ;
    move.b  ($0004,A4),D0
    move.b  ($0005,A4),D1
    cmp.b   D1,D0
    bcc  _anon_z01_101
    move.b  ($0008,A4),D1
    lsr.b  #1,D1   ; LSR $08
    move.b  D1,($0008,A4)
_anon_z01_101:
    ; If a monster is the defender, go handle it separately.
    ;
    cmpi.b  #$00,D3
    bne  _L_z01_BeginShove_MonsterDefender
    ; Link is the defender.
    ;
    ; If Link is invincible, return without shoving.
    ;
    move.b  ($04F0,A4),D0
    bne  _L_z01_BeginShove_Exit
    ; Store the shove direction we determined.
    ;
    ; Turn on the high bit to indicate that the next time we try to
    ; move by shoving, it will be the first time for this shove action.
    ;
    move.b  ($0008,A4),D0
    ori.b #$80,D0
    move.b  D0,($00C0,A4)
    ; Mark Link invincible $18 frames, and should move $20 pixels.
    ;
    moveq   #24,D0
    move.b  D0,($04F0,A4)
    moveq   #32,D0
    move.b  D0,($00D3,A4)
    ; If Link was shoved by one of his own weapons, then
    ; nothing else to do. Return.
    ;
    cmpi.b  #$0D,D2
    bcc  _L_z01_BeginShove_Exit
    ; Link was shoved by a monster.
    ;
    ; If the monster's object attribute "reverse after hit Link" is set,
    ; then return.
    ;
    lea     ($04BF,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$80,D0
    bne  _L_z01_BeginShove_Exit
    ; If the attacker is a vire, then return.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$12,D0
    beq  _L_z01_BeginShove_Exit
    ; Turn the attacker in the opposite direction.
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D2.W),D0
    jsr     GetOppositeDir
    lea     ($0098,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z01_BeginShove_Exit:
    rts

    even
_L_z01_BeginShove_MonsterDefender:
    ; A monster is the defender. A weapon is the attacker.
    ;
    ; Set the shove direction to the weapon's direction,
    ; instead of the direction passed in [0B].
    ;
    lea     ($0098,A4),A0
    move.b  (A0,D3.W),D0
    move.b  D0,($0008,A4)
    ; If the monster's attribute "reverse after hit Link" is set, then
    ; combine the shove direction with $40.
    ;
    ; TODO:
    ; But the shoving routing doesn't read this flag.
    ;
    lea     ($04BF,A4),A0
    move.b  (A0,D2.W),D0
    andi.b #$80,D0
    beq  _anon_z01_102
    move.b  ($0008,A4),D0
    ori.b #$40,D0
    move.b  D0,($0008,A4)
_anon_z01_102:
    ; If the monster is invincible, then return without shoving.
    ;
    lea     ($04F0,A4),A0
    move.b  (A0,D2.W),D0
    bne  _L_z01_BeginShove_Exit2
    ; If the monster is not a Gohma, then go store the shove direction.
    ;
    lea     ($034F,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$33,D0
    beq  _L_z01_BeginShove_Gohma
    cmpi.b  #$34,D0
    bne  _L_z01_BeginShove_SetShoveDir
    even
_L_z01_BeginShove_Gohma:
    ; This a Gohma, but if the current part [0F] is not an eye part (3 or 4),
    ; then return, so that the hit doesn't register.
    ;
    move.b  ($000F,A4),D0
    cmpi.b  #$03,D0
    beq  _anon_z01_103
    cmpi.b  #$04,D0
    bne  _L_z01_BeginShove_Exit2
_anon_z01_103:
    ; If Gohma's eye state/frame image <> 3, then return.
    ;
    lea     ($046B,A4),A0
    move.b  (A0,D2.W),D0
    cmpi.b  #$03,D0
    bne  _L_z01_BeginShove_Exit2
    even
_L_z01_BeginShove_SetShoveDir:
    ; Store the shove direction for the monster.
    ;
    ; Turn on the high bit to indicate that the next time we try to
    ; move by shoving, it will be the first time for this shove action.
    ;
    move.b  ($0008,A4),D0
    ori.b #$80,D0
    lea     ($00C0,A4),A0
    move.b  D0,(A0,D2.W)
    ; Mark the monster invincible $10 frames, and should move $40 pixels.
    ;
    moveq   #64,D0
    lea     ($00D3,A4),A0
    move.b  D0,(A0,D2.W)
    moveq   #16,D0
    lea     ($04F0,A4),A0
    move.b  D0,(A0,D2.W)
    even
_L_z01_BeginShove_Exit2:
    rts

    even
